/**
 * @fileoverview Core constants for the DUCAT Protocol Client SDK.
 *
 * This module defines protocol-level constants used throughout the SDK for
 * transaction construction, fee calculation, and validation. These values
 * are critical for protocol compatibility and should not be modified without
 * understanding their impact on transaction validity.
 */

import { OP_RETURN_CODE, SYMBOLS, TXMAP } from '@ducat-unit/core/const'

import SIGCOUNT from './const/sigcount.json' with { type: 'json' }
import TOPICS   from './const/topics.json'   with { type: 'json' }

import * as TXSIZE from './const/txsize.js'

import type { VaultAction } from '@ducat-unit/core'

export { SIGCOUNT, TOPICS, TXMAP, TXSIZE }

/** Number of satoshis in one Bitcoin. Used for BTC/UNIT price conversions. */
export const SATS_PER_BTC = 100_000_000n

/** BigInt constants for optimization and safe integer validation. */
export const BIGINT = { _0: BigInt(0), _MAX: BigInt(Number.MAX_SAFE_INTEGER) }

/** Number of decimal places to use for floating point numbers in calculations. */
export const FLOAT_PRECISION = 4

/** Valid script codes for transaction outputs (OP_RETURN, P2WPKH, P2TR). */
export const OUTPUT_CODES = [ OP_RETURN_CODE, 0x00, 0x51 ]

/**
 * Input codes that require guardian co-signatures via Taproot scripts.
 * These inputs represent vault state changes that need MPC group authorization.
 */
export const COSIGN_CODES = [
  ...Object.values(SYMBOLS.CODE.VAULT),
  SYMBOLS.CODE.INPUT.CONNECT,
] as const

/** Input codes that require liquidation signatures for under-collateralized vaults. */
export const LIQUID_CODES = [
  SYMBOLS.CODE.INPUT.LIQUID,
] as const

/** All input codes that require a guardian signature operation. */
export const SIGOPS_CODES = [ ...COSIGN_CODES, ...LIQUID_CODES ] as const

/** Tapscript leaf version for DUCAT protocol scripts (OP_CHECKSIGVERIFY). */
export const TAPLEAF_VERSION = 0x51

/** Default postage amount (in sats) for UTXOs carrying UNIT tokens. */
export const DEFAULT_POSTAGE = 1000

/** Bitcoin dust limit - minimum output value to prevent uneconomical UTXOs. */
export const DUST_LIMIT = 546

/**
 * Maximum allowed low-feerate tolerance (10%) — the hard ceiling for the
 * per-request `low_feerate_tolerance` option. The effective margin is opt-in
 * and defaults to 0 (strict); verification clamps any supplied value to
 * `[0, FEERATE_TOLERANCE]`, so an untrusted caller can never push the accepted
 * effective rate below `target * (1 - FEERATE_TOLERANCE)`. Accounts for minor
 * fee-estimation rounding / under-prediction without rejecting otherwise valid
 * transactions.
 */
export const FEERATE_TOLERANCE = 0.1

/** Vault actions that do not accept external funding inputs. */
export const NO_FUND_ACTIONS : VaultAction[] = [
  'close',
  'trim',
  'withdraw'
] as const

/**
 * Maximum number of guardians to account for in transaction size estimates.
 * This affects the pre-calculated witness sizes for multi-sig operations.
 * The protocol currently supports up to 3 guardians in the MPC group.
 */
export const MAX_GUARD_COUNT  = 3

/**
 * Maximum number of price oracles to account for in transaction size estimates.
 * Price commits from oracles are embedded in transactions for collateral ratio
 * validation. The protocol currently supports up to 3 oracle signatures.
 */
export const MAX_ORACLE_COUNT = 3

// The default PSBT configuration for the vault.
export const PSBT_CONFIG = {
  allowUnknownOutputs : true,
  version : 3
}

// The default timeout for a websocket subscription.
export const SUB_TIMEOUT = 5000

// The default vault version.
export const VAULT_VERSION = 1
