/**
 * @fileoverview Builds vault return-data from a vault request context.
 */

import { Assert } from '@vbyte/util'

import {
  select_base_price_commit,
  DEFAULT_RETURN_DATA
} from '@ducat-unit/core/lib'

import type { VaultReturnData }     from '@ducat-unit/core'
import type { VaultBaseRequestCtx } from '@/types/index.js'

/**
 * Build the vault return-data record from a vault request context. A
 * zero-balance vault returns the cleared default record (carrying the guard
 * members); a positive balance produces the priced return data from the
 * vault's price commits and stamp.
 *
 * @param vault_ctx - The vault base request context.
 * @returns The vault return-data record.
 */
export function create_vault_return_data (
  vault_ctx : VaultBaseRequestCtx
) : VaultReturnData {
  // Unpack the vault context.
  const { guard_members, price_commits, price_stamp, unit_balance } = vault_ctx
  // Get the guard indices.
  // If the unit balance is zero,
  if (unit_balance === 0) {
    // Return the default return data.
    return { ...DEFAULT_RETURN_DATA(), guard_members }
  } else {
    // Assert the unit balance is greater than zero.
    Assert.ok(unit_balance > 0, 'unit balance is not greater than zero')
    // Assert the price contracts and price stamp exist.
    Assert.exists(price_stamp,  'price stamp is missing from vault context')
    // Select the base price commit.
    const base_commit = select_base_price_commit(price_commits)
    // Assert the base price commit exists.
    Assert.exists(base_commit, 'base commit is missing from price commits')
    // Get the unit price and thold price.
    const unit_price  = base_commit.base_price
    const thold_price = base_commit.thold_price
    // Return the vault return data.
    return { guard_members, price_commits, unit_balance, unit_price, thold_price, price_stamp }
  }
}
