/**
 * @fileoverview Vault output builders for commit, connector, vault, and return outputs.
 */

import { Assert }                     from '@vbyte/util/assert'
import { encode_vault_return_script } from '@ducat-unit/core/lib'
import { DUST_LIMIT }                 from '@ducat-unit/core/const'
import { BIGINT }                     from '@/const.js'

import {
  create_taproot_script_key,
  get_address_script,
  create_connector_script,
  create_cleared_vault_script_tree,
  create_pledged_vault_script_tree,
  create_commit_script,
  create_vault_return_data
} from '@/module/vault/lib/index.js'

import type {
  PriceCommitData,
  PSBTOutput
} from '@ducat-unit/core'

import type { VaultRequestCtx } from '@/types/index.js'

/** Create taproot output carrying vault config commit inscription payload. */
export function create_vault_commit_vout (
  vault_ctx  : VaultRequestCtx,
  fund_value : number
) : PSBTOutput {
  // Assert that the vault config is defined.
  Assert.exists(vault_ctx.vault_config, 'vault config is missing from vault context')
  // Create the bitcoin script for the connector utxo.
  const scripts = [ create_commit_script(vault_ctx) ]
  // Create the taproot script.
  const script_pk = create_taproot_script_key(scripts)
  // Add the vault output.
  return { amount: BigInt(fund_value), script: script_pk }
}

/**
 * Create connector output controlled by the client + active guardian script path.
 * @param vault_ctx - Request context with client and guardian pubkeys.
 * @param fund_value - Output value in satoshis.
 * @returns Connector PSBT output.
 */
export function create_vault_connector_vout (
  vault_ctx  : VaultRequestCtx,
  fund_value : number
) : PSBTOutput {
  // Unpack the vault context.
  const { client_pubkey, guard_pubkey } = vault_ctx
  // Create the bitcoin script for the connector utxo.
  const scripts = [ create_connector_script(client_pubkey, guard_pubkey) ]
  // Create the taproot script.
  const script_pk = create_taproot_script_key(scripts)
  // Add the vault output.
  return { amount: BigInt(fund_value), script: script_pk }
}

/**
 * Create a pledged vault output (UNIT balance > 0).
 * @param client_pubkey - Client owner key.
 * @param guard_pubkeys - Allowed guardian pubkeys.
 * @param price_commits - Oracle commit set used for liquidation branches.
 * @param vault_amount - Output amount in satoshis.
 * @returns Vault PSBT output using pledged script tree.
 */
export function create_pledged_vault_output (
  client_pubkey : string,
  guard_pubkeys : string[],
  price_commits : PriceCommitData[],
  vault_amount  : number
) : PSBTOutput {
  // Assert that the price commits are defined.
  Assert.exists(price_commits, 'price commits are missing from vault context')
  // Create the bitcoin script for the vault utxo.
  const scripts = create_pledged_vault_script_tree(client_pubkey, guard_pubkeys, price_commits)
  // Create the taproot script.
  const script_pk = create_taproot_script_key(scripts)
  // Return the vault output.
  return { amount: BigInt(vault_amount), script: script_pk }
}

/**
 * Create a cleared vault output (UNIT balance = 0).
 * @param client_pubkey - Client owner key.
 * @param guard_pubkeys - Allowed guardian pubkeys.
 * @param vault_amount - Output amount in satoshis.
 * @returns Vault PSBT output using cleared script tree.
 */
export function create_cleared_vault_output (
  client_pubkey : string,
  guard_pubkeys : string[],
  vault_amount  : number
) : PSBTOutput {
  // Create the bitcoin script for the vault utxo.
  const scripts   = create_cleared_vault_script_tree(client_pubkey, guard_pubkeys)
  // Create the taproot script.
  const script_pk = create_taproot_script_key(scripts)
  // Return the vault output.
  return { amount: BigInt(vault_amount), script: script_pk }
}

/**
 * Create the next vault output by dispatching on post-action UNIT balance.
 * @param vault_ctx - Request context with script participants and terms.
 * @param unit_balance - Post-action UNIT balance.
 * @param vault_balance - Post-action net collateral balance (excluding min value floor).
 * @returns Pledged or cleared vault output depending on `unit_balance`.
 */
export function create_vault_output (
  vault_ctx     : VaultRequestCtx,
  unit_balance  : number,
  vault_balance : number
) : PSBTOutput {
  // Unpack the vault context.
  const { client_pubkey, guard_members, price_commits, vault_terms } = vault_ctx
  // Validate guard_members contains the active guardian.
  Assert.ok(
    guard_members.includes(vault_ctx.guard_pubkey),
    'active guardian pubkey is not in guard_members list'
  )
  // Define the vault amount.
  const vault_amount = vault_balance + vault_terms.vault_value_min
  // If the unit balance is greater than 0,
  if (unit_balance > 0) {
    return create_pledged_vault_output(client_pubkey, guard_members, price_commits, vault_amount)
  } else {
    return create_cleared_vault_output(client_pubkey, guard_members, vault_amount)
  }
}

/**
 * Create standard BTC change output for the caller.
 * @param vault_ctx - Request context containing change address.
 * @param change_amt - Change amount in satoshis.
 * @returns Change PSBT output.
 */
export function create_sats_change_output (
  vault_ctx  : VaultRequestCtx,
  change_amt : number
) : PSBTOutput {
  const { change_address } = vault_ctx
  // Assert the change address is present.
  Assert.exists(change_address, 'change address is missing from vault context')
  // Assert the change amount is at least the dust limit.
  Assert.ok(change_amt >= DUST_LIMIT, `change amount is below dust limit (${DUST_LIMIT})`)
  // Create the bitcoin script for the change output.
  const script = get_address_script(change_address)
  // Return the change output.
  return { amount: BigInt(change_amt), script }
}

/**
 * Create OP_RETURN payload output with encoded vault return data.
 * @param vault_ctx - Request context used to build return payload.
 * @returns Zero-valued OP_RETURN PSBT output.
 */
export function create_vault_return_output (
  vault_ctx : VaultRequestCtx,
) : PSBTOutput {
  // Unpack the vault context.
  const { proto_profile } = vault_ctx
  // Create the bitcoin script for the return output.
  const return_data = create_vault_return_data(vault_ctx)
  // Assert the return data is defined.
  const script_pk   = encode_vault_return_script(proto_profile, return_data)
  // Return an OP_RETURN data script with the encoded payload.
  return { amount : BIGINT._0, script: script_pk }
}
