/**
 * @fileoverview Builders for asset issue and burn return-data (OP_RETURN) scripts.
 */

import { create_asset_transfer_script } from '@ducat-unit/core/lib'
import { TXMAP }                        from '@/const.js'
import { get_unit_asset_id }            from './asset_id.js'

import type {
  ProtoProfile
} from '@ducat-unit/core'

const UNIT_BURN_VOUT = TXMAP.UNIT_REPAY.VOUT.RDATA
const UNIT_XFER_VOUT = TXMAP.UNIT_ISSUE.VOUT.UNIT

/**
 * Create a PSBT output that is configured as a UNIT issuance utxo.
 * @param data : A data object that configures the UNIT issuance.
 * @returns
 */
export function create_asset_issue_return_script (
  proto_profile : ProtoProfile,
  borrow_amount : number
) : Uint8Array {
  // Create the asset transfer edict.
  return create_asset_transfer_script({
    asset_id  : get_unit_asset_id(proto_profile),
    amount    : borrow_amount,
    output    : UNIT_XFER_VOUT
  })
}

/**
 * Create a PSBT output that is configured as a UNIT repayment utxo.
 * @param data : A data object that configures the UNIT repayment.
 * @returns
 */
export function create_asset_burn_return_script (
  proto_profile : ProtoProfile,
  burn_amount   : number
) : Uint8Array {
  // Create the asset transfer edict.
  return create_asset_transfer_script({
    asset_id  : get_unit_asset_id(proto_profile),
    amount    : burn_amount,
    output    : UNIT_BURN_VOUT
  })
}
