/**
 * @fileoverview Zod schemas for Esplora transaction, block, and UTXO data.
 */

import { z } from 'zod'

import { base } from '@ducat-unit/core/schema'

import type {
  EsploraAddressUtxo,
  EsploraBlockData,
  EsploraTxCoinbase,
  EsploraTxData,
  EsploraTxInput,
  EsploraTxOutput
} from '@/types/index.js'

export const address_utxo = z.object({
  txid   : base.hex32,
  vout   : base.uint,
  value  : base.uint
}) satisfies z.ZodType<EsploraAddressUtxo>

export const tx_output = z.object({
  scriptpubkey : base.hex,
  value        : base.uint
}) satisfies z.ZodType<EsploraTxOutput>

export const tx_coinbase = z.object({
  is_coinbase : z.literal(true),
  prevout     : z.null(),
  txid        : base.hex32,
  vout        : base.uint,
  scriptsig   : base.hex,
  sequence    : base.uint,
  witness     : base.hex.array()
}) satisfies z.ZodType<EsploraTxCoinbase>

export const tx_input = z.object({
  is_coinbase : z.literal(false),
  txid        : base.hex32,
  vout        : base.uint,
  prevout     : tx_output,
  scriptsig   : base.hex,
  sequence    : base.uint,
  witness     : base.hex.array()
}) satisfies z.ZodType<EsploraTxInput>

export const tx_data = z.object({
  locktime : base.uint,
  txid     : base.hex32,
  version  : base.uint,
  vin      : z.array(tx_input),
  vout     : z.array(tx_output)
}) satisfies z.ZodType<EsploraTxData>

export const block_data = z.object({
  hash   : base.hex32,
  height : base.uint,
  prev   : base.hex32,
  stamp  : base.uint,
  tx     : z.array(tx_data)
}) satisfies z.ZodType<EsploraBlockData>
