/**
 * @fileoverview Fee estimation for vault actions.
 *
 * This module calculates transaction fees using dynamic size calculation:
 *
 * 1. Dynamic size calculation: Computes transaction sizes based on actual
 *    config parameters (guard count, price commits, input counts, etc.)
 *
 * 2. Variable components included:
 *    - Taproot control block size (varies with script tree depth)
 *    - Sigops weight (signature verification cost)
 *    - Conditional outputs (change, asset change, reserve)
 *    - Variable input counts (funding, asset, liquidation)
 *
 * 3. Fee calculation: vsize × fee_rate = total fees
 *
 * Key improvements over static estimation:
 * - Control block size varies with tree depth (guard count × price commits)
 * - Sigops are included in the calculation
 * - Conditional outputs are properly accounted for
 */
import {
  emit_debug,
  validate_action_config,
  get_effective_vsize,
  get_observe_context,
  get_vault_action_tx_vsize,
  get_vault_action_sigops_count,
  get_vault_action_sigops_vsize,
  get_vault_action_postage,
  with_observe_span,
  create_vault_action_context,
} from '@/lib/index.js'

import type {
  VaultActionConfig,
  VaultActionEstimate
} from '@/types/index.js'

/**
 * Creates a fee estimate for a vault action transaction.
 *
 * The estimate includes:
 * - action_vsize: Virtual size of the transaction in vbytes
 * - action_fees: Total fees based on vsize × fee_rate
 * - action_postage: Postage amount for UNIT-bearing outputs
 * - action_value: Total value needed (deposit + fees + postage + reserve)
 *
 * @param vault_config - Configuration containing action type, amounts, and fee rate
 * @returns VaultActionEstimate with size, fee, and value calculations
 * @throws If the vault config fails validation
 */
export function create_vault_action_estimate (
  action_config : VaultActionConfig
) : VaultActionEstimate {
  const observe = get_observe_context(action_config.observability, {
    module       : 'vault.estimate',
    vault_action : action_config.vault_action
  })

  return with_observe_span(
    observe,
    `vault.${action_config.vault_action}.estimate`,
    { vault_action : action_config.vault_action },
    scope => {
      // Validate the vault config.
      validate_action_config(action_config)
      // Unpack the vault config.
      const {
        txfee_rate,
        txfee_reserve  = 0,
        deposit_amount = 0
      } = action_config
      // Calculate the context.
      const action_ctx = create_vault_action_context(action_config)
      // Calculate the transaction size dynamically.
      const action_vsize = get_vault_action_tx_vsize(action_config, action_ctx)
      // Get sigops count for this action path.
      const action_sigops_count = get_vault_action_sigops_count(action_config)
      // Add sigops overhead to match effective fee-rate checks in request verification.
      const action_sigops_vsize = get_vault_action_sigops_vsize(action_config)
      const action_effective_vsize = get_effective_vsize({
        tx_vsize      : action_vsize,
        sigops_count  : action_sigops_count
      })
      // Calculate the transaction fees using effective vsize.
      const action_fees = action_effective_vsize * txfee_rate
      // Calculate the action postage.
      const action_postage = get_vault_action_postage(action_config)
      // Calculate the total cost.
      const action_value = deposit_amount + action_fees + action_postage + txfee_reserve
      // Return the vault action estimate.
      const estimate = {
        ...action_ctx,
        action_effective_vsize,
        action_fees,
        action_postage,
        action_sigops_vsize,
        action_value,
        action_vsize
      }
      emit_debug(scope, `vault.${action_config.vault_action}.estimate.complete`, {
        action_effective_vsize,
        action_fees,
        action_postage,
        action_vsize,
        guardian_count : estimate.guardian_count,
        oracle_count   : estimate.oracle_count
      })
      return estimate
    }
  )
}
