/**
 * @fileoverview No-op observability implementations.
 */

import type {
  LogEvent,
  LogLevel,
  SdkLogger,
  SdkTracer,
  TraceSpan
} from './types.js'

// W3C invalid-context zero strings: trace IDs are 16 bytes (32 hex), span
// IDs are 8 bytes (16 hex). Matches what the OTel API returns when no
// provider is installed, keeping no-op IDs consistent with the adapter.
export const NOOP_SPAN : TraceSpan = {
  trace_id : '0'.repeat(32),
  span_id  : '0'.repeat(16),
  event    : () => {},
  end      : () => {},
  fail     : () => {}
}

export const NOOP_LOGGER : SdkLogger = {
  enabled : (_level : LogLevel) => false,
  emit    : (_event : LogEvent) => {}
}

export const NOOP_TRACER : SdkTracer = {
  start_span : () => NOOP_SPAN
}
