/**
 * @fileoverview Custom error types for the DUCAT Client SDK.
 */

import type { ZodError } from 'zod'

/**
 * Extended error options that include Zod error details.
 */
export interface ValidationErrorOptions extends ErrorOptions {
  zod_error?: ZodError
}

/**
 * Base error class for all DUCAT SDK errors.
 */
export class DucatError extends Error {
  readonly code: string

  constructor (message: string, code: string = 'DUCAT_ERROR', options?: ErrorOptions) {
    super(message, options)
    this.name = 'DucatError'
    this.code = code
    // Maintains proper stack trace for where our error was thrown (only available on V8)
    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, this.constructor)
    }
  }
}

/**
 * Error class for WebSocket connection and communication issues.
 */
export class WebSocketError extends DucatError {
  constructor (message: string, options?: ErrorOptions) {
    super(message, 'WEBSOCKET_ERROR', options)
    this.name = 'WebSocketError'
  }
}

/**
 * Error class for vault operation failures.
 */
export class VaultError extends DucatError {
  constructor (message: string, options?: ErrorOptions) {
    super(message, 'VAULT_ERROR', options)
    this.name = 'VaultError'
  }
}

/**
 * Error class for input validation failures.
 * Captures Zod validation errors with detailed issue information.
 */
export class ValidationError extends DucatError {
  readonly zod_error?: ZodError
  readonly details: string[]

  constructor (message: string, options?: ValidationErrorOptions) {
    super(message, 'VALIDATION_ERROR', options)
    this.name = 'ValidationError'
    this.zod_error = options?.zod_error
    this.details = this.zod_error
      ? this.zod_error.issues.map(i => `${i.path.join('.')}: ${i.message}`)
      : [message]
  }
}

/**
 * Error class for guardian communication failures.
 *
 * Intentional public API: the SDK's guard layer is Result-typed — request
 * helpers return `{ ok: false, reason }` rather than throwing — so the SDK
 * itself does not throw this. It is exported for consumers who convert a
 * failed guardian result into an exception (`throw new GuardianError(reason)`).
 */
export class GuardianError extends DucatError {
  constructor (message: string, options?: ErrorOptions) {
    super(message, 'GUARDIAN_ERROR', options)
    this.name = 'GuardianError'
  }
}
