/**
 * @fileoverview Logging helpers for observability-aware modules.
 */

import { redact_observe_fields } from './redact.js'

import type {
  LogLevel,
  ObserveContext
} from './types.js'

function format_error (error : unknown) {
  if (error instanceof Error) {
    return {
      error_message : error.message,
      error_name    : error.name
    }
  }
  return {
    error_message : String(error),
    error_name    : 'Error'
  }
}

function emit_log (
  context : ObserveContext,
  level   : LogLevel,
  name    : string,
  message : string | undefined,
  fields  : Record<string, unknown>
) {
  if (!context.logger.enabled(level)) return

  const merged = redact_observe_fields(
    { ...context.fields, ...fields },
    context.redact_sensitive,
    context.unsafe_payloads
  )

  context.logger.emit({
    level,
    name,
    time     : new Date().toISOString(),
    fields   : merged,
    message,
    span_id  : context.span?.span_id,
    trace_id : context.span?.trace_id
  })
}

/**
 * Emit a structured debug-level log event for `name` with optional fields.
 *
 * @param context - The active observe context (carries span/trace ids).
 * @param name    - The event name.
 * @param fields  - Optional structured fields.
 */
export function emit_debug (
  context : ObserveContext,
  name    : string,
  fields  : Record<string, unknown> = {}
) {
  emit_log(context, 'debug', name, undefined, fields)
}

/**
 * Emit a structured error-level log event for `name`, capturing `message` and
 * the formatted `error`.
 *
 * @param context - The active observe context (carries span/trace ids).
 * @param name    - The event name.
 * @param message - The human-readable error message.
 * @param error   - The error value (formatted into fields).
 * @param fields  - Optional structured fields.
 */
export function emit_error (
  context : ObserveContext,
  name    : string,
  message : string,
  error   : unknown,
  fields  : Record<string, unknown> = {}
) {
  emit_log(context, 'error', name, message, { ...fields, ...format_error(error) })
}

/**
 * Emit a structured info-level log event for `name` with `message` and optional fields.
 *
 * @param context - The active observe context (carries span/trace ids).
 * @param name    - The event name.
 * @param message - The human-readable message.
 * @param fields  - Optional structured fields.
 */
export function emit_info (
  context : ObserveContext,
  name    : string,
  message : string,
  fields  : Record<string, unknown> = {}
) {
  emit_log(context, 'info', name, message, fields)
}

/**
 * Emit a structured warn-level log event for `name` with `message` and optional fields.
 *
 * @param context - The active observe context (carries span/trace ids).
 * @param name    - The event name.
 * @param message - The human-readable message.
 * @param fields  - Optional structured fields.
 */
export function emit_warn (
  context : ObserveContext,
  name    : string,
  message : string,
  fields  : Record<string, unknown> = {}
) {
  emit_log(context, 'warn', name, message, fields)
}
