/**
 * @fileoverview Script-sizing helpers for fee planning.
 */

import { Test }       from '@vbyte/util'
import { VaultError } from '@/lib/errors/index.js'

/**
 * Estimate script virtual size units from raw bytes or hex.
 *
 * `vsize` is approximated as `ceil(bytes / 4)` for fee planning.
 */
export function calc_script_vsize (script : string | Uint8Array) : number {
  // Initialize the size.
  let size = 0
  // If the script is a Uint8Array, calculate the size.
  if (script instanceof Uint8Array) size = script.length
  // If the script is a hex string, calculate the size.
  else if (Test.is_hex(script))     size = script.length / 2
  // Otherwise, throw an error.
  else throw new VaultError(`invalid script type: ${typeof script}`)
  // Return the size.
  return Math.ceil(size / 4)
}
