/**
 * @fileoverview Coin (UTXO) sizing and funding-context helpers for transaction construction.
 */

import { Assert }               from '@vbyte/util/assert'
import { get_lock_script_type } from '@vbyte/btc-dev/script'
import { get_coin_total_value } from '@ducat-unit/core/lib'
import { TXSIZE }               from '@/const.js'

import type { CoinUtxo }          from '@ducat-unit/core'
import type { VaultFundsContext } from '@/types/vault.js'

export const FUNDS_CTX : VaultFundsContext = {
  coin_count : 0,
  coin_fees  : 0,
  coin_size  : 0,
  coin_value : 0
}

/** Estimate virtual input size for a coin based on lock script type. */
export function get_coin_size (coin : CoinUtxo) : number {
  // Get the coin type.
  const type = get_lock_script_type(coin.script_pk)
  // Assert that the coin type is valid.
  Assert.exists(type, `unsupported coin type: ${coin.script_pk}`)
  // Return the coin size based on the type.
  switch (type) {
    case 'p2wpkh': return TXSIZE.VIN_P2WPKH_SPEND_SIZE
    case 'p2tr':   return TXSIZE.VIN_P2TR_SPEND_SIZE
    default:       throw new Error(`unsupported coin type: ${type}`)
  }
}

/** Sum estimated input vsize across a set of coins. */
export function get_coin_total_size (
  coin_utxos : CoinUtxo[]
) : number {
  let total_size = 0
  for (const coin of coin_utxos) {
    // Get the coin size.
    total_size += get_coin_size(coin)
  }
  // Return the total coin size.
  return total_size
}

/** Build aggregate coin/funding context for fee and value calculations. */
export function get_coin_ctx (
  coin_inputs : CoinUtxo[],
  txfee_rate  : number
) : VaultFundsContext {
  // Return the default context if there are no coins.
  if (coin_inputs.length === 0) return FUNDS_CTX
  // Get the coin count.
  const coin_count     = coin_inputs.length
  // Get the coin size.
  const coin_size      = get_coin_total_size(coin_inputs)
  // Get the coin value.
  const coin_value     = get_coin_total_value(coin_inputs)
  // Define the coin fees.
  const coin_fees      = coin_size * txfee_rate
  // Return the coin spend context.
  return { coin_count, coin_fees, coin_size, coin_value }
}
