/**
 * @fileoverview Vault Repo (Liquidation) API - Process under-collateralized vaults.
 *
 * The repo (repossession) action liquidates vaults that have fallen below the
 * minimum collateral ratio. This protects the protocol by ensuring all UNIT
 * tokens remain fully backed.
 *
 * ## Liquidation Process
 *
 * 1. Oracle prices fall, pushing vault below liquidation threshold
 * 2. Liquidator fetches breached vault profiles from validator
 * 3. Liquidator constructs repo transaction with guardian signature
 * 4. Vault collateral is claimed to cover the outstanding debt
 *
 * ## Single-Transaction Pattern
 *
 * Repo uses a single PSBT with a special liquidation script path that
 * requires both guardian signature and proof of breach.
 *
 * ## Usage
 *
 * ```typescript
 * import { VaultRepoAPI } from '@ducat-unit/client-sdk/vault'
 *
 * const ctx = VaultRepoAPI.create_ctx(config)
 * const psbt = VaultRepoAPI.create_psbt(ctx)
 * const signed = await wallet.sign.psbt(psbt)
 * const request = VaultRepoAPI.create_request(ctx, signed)
 * ```
 *
 * @module vault/api/repo
 */

import { get_txid }    from '@vbyte/btc-dev/tx'
import { Assert }      from '@vbyte/util'
import { PSBT }        from '@ducat-unit/core'
import {
  emit_info,
  with_observe_span
} from '@/lib/observe/index.js'

import { PSBT_CONFIG, DUST_LIMIT } from '@/const.js'

import {
  create_liquid_vault_cleared_output,
  create_sats_change_output,
  create_vault_return_output,
  create_vault_spend_input,
  create_vault_output,
  create_reserve_spend_output,
  finalize_spending_inputs,
  finalize_cosign_inputs,
  create_liquid_spend_vin,
  verify_vault_request_psbt,
  verify_vault_action_rules,
  create_vault_ctx,
  validate_vault_repo_config,
  create_vault_request,
  validate_vault_repo_request,
  finalize_liquid_inputs,
  extract_guardian_sighashes
} from '../lib/index.js'

import type {
  VaultRepoRequest
} from '@ducat-unit/core'
import type {
  VaultRepoRequestCtx,
  VaultRepoRequestConfig
} from '@/types/index.js'

/**
 * Create a context object for a Vault Repo action.
 *
 * @param vault_config - User-provided vault-repo configuration.
 * @returns Validated vault-repo request context.
 */
export function create_vault_repo_ctx (
  vault_config : VaultRepoRequestConfig
) : VaultRepoRequestCtx {
  // Validate the configuration for a vault repo action.
  validate_vault_repo_config(vault_config)
  // Return the vault context object.
  return create_vault_ctx(vault_config)
}

/**
 * Create the liquidation PSBT for vault-repo.
 *
 * @param vault_ctx - Vault-repo request context.
 * @returns Encoded vault-repo PSBT.
 */
export function create_vault_repo_psbt (
  vault_ctx : VaultRepoRequestCtx
) {
  return with_observe_span(
    vault_ctx.observe,
    'vault.repo.create_psbt',
    {
      fund_input_count   : vault_ctx.fund_inputs.length,
      liquid_vault_count : vault_ctx.liquid_profiles.length
    },
    scope => {
      const { fund_inputs, change_value, liquid_profiles, reserve_balance, vault_terms, unit_balance, vault_balance } = vault_ctx
      const reserve_value_min = vault_terms.reserve_sats_min
      const vault_value_min   = vault_terms.vault_value_min
      const pdata = PSBT.create_psbt(PSBT_CONFIG)
      pdata.addOutput(create_vault_output(vault_ctx, unit_balance, vault_balance))
      for (const vault_profile of liquid_profiles) {
        pdata.addOutput(create_liquid_vault_cleared_output(vault_profile, vault_value_min))
      }
      if (change_value >= DUST_LIMIT) {
        pdata.addOutput(create_sats_change_output(vault_ctx, change_value))
      }
      if (reserve_balance >= reserve_value_min) {
        pdata.addOutput(create_reserve_spend_output(vault_ctx, reserve_balance))
      }
      pdata.addOutput(create_vault_return_output(vault_ctx))
      pdata.addInput(create_vault_spend_input(vault_ctx))
      for (const vault of liquid_profiles) {
        pdata.addInput(create_liquid_spend_vin(vault))
      }
      for (const utxo of fund_inputs) {
        pdata.addInput(PSBT.create_psbt_input(utxo))
      }
      PSBT.assert_is_funded(pdata)
      const psbt = PSBT.encode_psbt(pdata)
      emit_info(scope, 'vault.repo.psbt.created', 'created vault repo PSBT', {
        psbt_length : psbt.length
      })
      return psbt
    }
  )
}

/**
 * Create a signed guardian request payload for vault-repo.
 *
 * @param vault_ctx - Vault-repo request context.
 * @param vault_psbt - Signed vault-repo PSBT.
 * @returns Validated vault-repo request payload.
 */
export function create_vault_repo_request (
  vault_ctx  : VaultRepoRequestCtx,
  vault_psbt : string
) : VaultRepoRequest {
  return with_observe_span(
    vault_ctx.observe,
    'vault.repo.create_request',
    { signed_psbt_length : vault_psbt.length },
    scope => {
      Assert.exists(vault_psbt, 'vault PSBT is undefined')
      const context     = create_vault_request(vault_ctx)
      const vault_pdata = PSBT.parse_psbt(vault_psbt)
      finalize_cosign_inputs(vault_pdata)
      finalize_liquid_inputs(vault_pdata)
      finalize_spending_inputs(vault_pdata)
      const sighashes = extract_guardian_sighashes(vault_pdata)
      verify_vault_request_psbt(vault_pdata, vault_ctx.txfee_rate, { ...vault_ctx.validation_options, observe: vault_ctx.observe })
      const vault_txid = get_txid(vault_pdata.hex)
      verify_vault_action_rules(vault_ctx, vault_txid)
      vault_psbt = PSBT.encode_psbt(vault_pdata)
      const request = { ...context, sighashes, vault_psbt, vault_txid }
      validate_vault_repo_request(request)
      emit_info(scope, 'vault.repo.request.created', 'created vault repo guardian request', {
        vault_txid
      })
      return request
    }
  )
}

/**
 * Export the API for the vault repo action.
 */
export namespace VaultRepoAPI {
  export const create_ctx     = create_vault_repo_ctx
  export const create_psbt    = create_vault_repo_psbt
  export const create_request = create_vault_repo_request
}
