/**
 * @fileoverview Guardian API call for the vault open action.
 */

import { GuardianClient }     from '@/module/guard/class/client.js'
import { SocketSubscription } from '@/class/socket.js'
import { TOPICS }             from '@/const.js'
import { child_observe_context, emit_debug, emit_info, emit_warn } from '@/lib/observe/index.js'

import { validate_vault_open_request } from '@/module/vault/lib/validate.js'

import type {
  VaultOpenResponse,
  VaultOpenRequest
} from '@ducat-unit/core'
import type {
  MessageData
} from '@/types/index.js'

import * as SCHEMA from '@/schema/index.js'
import * as SHARED from '@ducat-unit/core/schema'

/** Build a subscription API for guardian vault-open signing requests. */
export function open_vault_api (client : GuardianClient) {

  return (request : VaultOpenRequest) : SocketSubscription<VaultOpenResponse> => {

    validate_vault_open_request(request)

    const msg = { data : request, topic : TOPICS.GUARDIAN.VAULT_OPEN }
    const sub = client.socket.subscribe<VaultOpenResponse>(msg)
    const observe = child_observe_context(client.observe, {
      contract_id : request.contract_id,
      request_id  : sub.id,
      topic       : msg.topic,
      vault_action: request.vault_action
    })

    emit_info(
      observe,
      'guardian.request.vault.open.start',
      'created guardian vault open request',
      { contract_id : request.contract_id }
    )

    sub.on('message', (message : MessageData) => {
      switch (message.type) {
        case 'info': {
          const parsed = SHARED.base.str.parse(message.data)
          emit_info(observe, 'guardian.request.subscription.info', parsed)
          sub.emit('info', parsed)
          break
        }
        case 'reject': {
          const parsed = SHARED.base.str.parse(message.data)
          emit_warn(observe, 'guardian.request.vault.open.reject', 'guardian vault open request rejected', {
            reason : parsed
          })
          sub.emit('reject', parsed)
          break
        }
        case 'result': {
          const schema = SCHEMA.module.guard.response.vault_open
          const parsed = schema.parse(message.data)
          emit_debug(observe, 'guardian.request.vault.open.result', {
            issue_txid : parsed.issue_txid,
            vault_txid : parsed.vault_txid
          })
          sub.emit('result', parsed)
          break
        }
        case 'status': {
          const parsed = SHARED.base.str.parse(message.data)
          emit_info(observe, 'guardian.request.subscription.status', parsed)
          sub.emit('status', parsed)
          break
        }
      }
    })

    return sub
  }
}
