/**
 * @fileoverview Validator API fetch helpers for protocol profile data and history.
 */

import { Fetch, Resolve }          from '@vbyte/util'
import {
  validate_fetch_response
} from './util.js'
import * as SHARED                 from '@ducat-unit/core/schema'
import * as SCHEMA                 from '@/schema/index.js'

import type { ProtoProfile } from '@ducat-unit/core'
import type { ProtoHistoryRecord } from '@/types/index.js'

/**
 * Fetches protocol profile from the validator API
 * @param host_url - Base URL of the validator API server
 * @returns Protocol profile data or error response
 */
export async function fetch_proto_data (
  host_url : string
) : Promise<Resolve.Type<ProtoProfile>> {
  const url = `${host_url}/api/proto/latest`
  const res = await Fetch.json(url)
  if (!res.ok) return res
  return validate_fetch_response(
    SHARED.proto.profile,
    res.data,
    'protocol profile validation failed'
  )
}

/**
 * Fetches protocol configuration history from the validator API
 * @param host_url - Base URL of the validator API server
 * @returns Array of protocol profile data or error response
 */
export async function fetch_proto_history (
  host_url : string
) : Promise<Resolve.Type<ProtoHistoryRecord[]>> {
  const res = await Fetch.json(`${host_url}/api/proto/history`)
  if (!res.ok) return res
  return validate_fetch_response(
    SCHEMA.fetch.proto_history_record.array(),
    res.data,
    'protocol history validation failed'
  )
}
