/**
 * @fileoverview Vault request verification utilities.
 *
 * Provides validation functions for vault operations:
 * - Price contract data verification
 * - Collateral ratio validation against protocol minimums
 * - PSBT structure and fee rate verification
 *
 * ## Security Notes
 *
 * - Low fee rates throw by default; a bounded, opt-in `low_feerate_tolerance`
 *   (default 0, capped at `FEERATE_TOLERANCE`) may downgrade a within-margin
 *   shortfall to a warning. Over-payment past the high thresholds throws too.
 * - Amount calculations use BigInt for precision safety
 * - Script code validation ensures only allowed output types
 *
 * @module vault/lib/verify
 */

import { Assert }         from '@vbyte/util'
import { get_txsize }     from '@vbyte/btc-dev/tx'
import { OP_RETURN_CODE, SYMBOLS } from '@ducat-unit/core/const'

import { emit_warn } from '@/lib/observe/index.js'

import type { ObserveContext } from '@/lib/observe/index.js'

import {
  calc_collateral_ratio,
  decode_sequence,
  select_base_price_commit,
  verify_price_contract_signature,
  verify_oracles_authorized,
  verify_vault_open_strict,
  eval_vault_open_policy,
  verify_vault_borrow_strict,
  eval_vault_borrow_policy,
  verify_vault_repay_strict,
  eval_vault_repay_policy,
  verify_vault_deposit,
  verify_vault_withdraw_strict,
  eval_vault_withdraw_policy,
  verify_vault_close,
  is_authorized_signer,
  is_valid_unit_balance
} from '@ducat-unit/core/lib'

import {
  get_adjusted_commit_price
} from '@/lib/vault/util.js'

import {
  verify_liquidator_vault_transition,
  verify_liquid_vaults_eligible,
  verify_liquid_vault_transitions,
  verify_liquidation_amounts
} from './verify_liquidation.js'

import {
  BIGINT,
  DUST_LIMIT,
  OUTPUT_CODES,
  SIGOPS_CODES
} from '@/const.js'

import {
  get_effective_feerate,
  get_effective_vsize,
  get_min_feerate
} from '@/lib/vault/feerate.js'

// Fee rate validation thresholds
const FEERATE_WARN_MULTIPLIER  = 1.5  // Warn at 1.5x expected
const FEERATE_ERROR_MULTIPLIER = 3.0  // Error at 3x expected

import type { PolicyFlag, PSBTData, VaultAction, VaultProfile } from '@ducat-unit/core'

import type {
  VaultBaseRequestConfig,
  VaultRequestCtx
} from '@/types/index.js'

/**
 * Throw on the first policy flag, preserving the reject-everything behavior the
 * core composites previously provided. Strict checks run separately at the call
 * site; this turns any non-empty policy result into a hard rejection.
 */
function reject_on_policy_flags (label : string, flags : PolicyFlag[]) : void {
  if (flags.length > 0) {
    throw new Error(`${label} [${flags[0].code}]: ${flags[0].detail}`)
  }
}

// Curing actions only improve the vault (pay down debt and/or add collateral),
// so the strict request-time collateral-ratio floor must NOT apply to them:
// requiring the post-state ratio to reach the protocol minimum would wrongly
// reject an improving partial repay on a vault that is already below the
// minimum. Their bounds are governed by the per-action repay policy
// (eval_vault_repay_policy: must-not-worsen + floor on any withdrawal) and the
// strict verifier (verify_vault_repay_strict: debt must strictly decrease).
const CURING_ACTIONS : readonly VaultAction[] = ['repay', 'deposit']

/**
 * Whether an action must satisfy the request-time collateral-ratio floor.
 * Debt-increasing / collateral-reducing actions (open, borrow, withdraw) must;
 * curing actions (repay, deposit) must not — see {@link CURING_ACTIONS}.
 *
 * @param action - The vault action being requested.
 * @returns `true` if the strict floor applies, `false` for curing actions.
 */
export function action_requires_collateral_floor (action : VaultAction) : boolean {
  return !CURING_ACTIONS.includes(action)
}

export function verify_vault_request_ctx (vault_ctx : VaultRequestCtx<VaultBaseRequestConfig>) {
  // Every vault is guardian-cosigned: the guardian set that the request
  // locks the vault to must be authorized by the protocol profile,
  // regardless of debt state (Codex F02/F04).
  verify_guards_authorized(vault_ctx)
  // The resulting debt position must be either cleared or above the
  // protocol dust minimum, in any debt state (Codex F21).
  verify_unit_balance(vault_ctx)
  if (vault_ctx.unit_balance > 0) {
    // Verify the price contract data.
    verify_price_contract_data(vault_ctx)
    // Verify the price contract signatures.
    verify_price_contract_signatures(vault_ctx)
    // Verify the price oracles are authorized.
    verify_price_oracles_authorized(vault_ctx)
    // Verify the collateral ratio — but only for non-curing actions. A curing
    // action (repay/deposit) on a sub-minimum vault improves the position and
    // must be allowed even when the result is still below the protocol minimum.
    if (action_requires_collateral_floor(vault_ctx.vault_action)) {
      verify_collateral_ratio(vault_ctx)
    }
  }
}

/**
 * Verify every guardian the request locks the vault to is an authorized
 * GUARD-group signer in the protocol profile (Codex F02/F04).
 *
 * guard_members arrive from the request config (or the prior vault
 * profile) and were previously trusted as-is — a borrower could lock a
 * vault to non-guardian or attacker-controlled pubkeys, or supply
 * guards filtered against the wrong signer group. The GUARD-group
 * membership check is the canonical core predicate.
 */
export function verify_guards_authorized (vault_ctx : VaultRequestCtx<VaultBaseRequestConfig>) {
  const { guard_members, proto_profile } = vault_ctx
  Assert.ok(guard_members.length > 0, 'vault must lock to at least one guardian')
  for (const pubkey of guard_members) {
    Assert.ok(
      is_authorized_signer(proto_profile, pubkey, SYMBOLS.SIGNER.GUARDIAN),
      `guardian is not an authorized protocol GUARD-group signer: ${pubkey}`
    )
  }
}

/**
 * Verify the resulting vault debt is either fully cleared or at/above the
 * protocol's minimum unit balance (Codex F21).
 *
 * The minimum was previously dropped, leaving only a `>= 0` check, which
 * allowed dust-debt positions below `unit_balance_min` to be produced
 * through the SDK. The threshold lives in `proto_terms`, so the canonical
 * `0 || >= unit_balance_min` predicate is the core primitive.
 */
export function verify_unit_balance (vault_ctx : VaultRequestCtx<VaultBaseRequestConfig>) {
  const { unit_balance, vault_terms } = vault_ctx
  Assert.ok(
    is_valid_unit_balance(unit_balance, vault_terms),
    `vault debt is below protocol minimum: ${unit_balance} < ${vault_terms.unit_balance_min}`
  )
}

/**
 * Verify the oracle signatures on all price contracts.
 * Each price contract must have a valid BIP-340 signature from the oracle.
 */
export function verify_price_contract_signatures (vault_ctx : VaultRequestCtx<VaultBaseRequestConfig>) {
  const { price_contracts } = vault_ctx
  // If no price contracts, skip.
  if (!price_contracts || price_contracts.length === 0) return
  // Verify each price contract signature (structural + BIP-340).
  for (const contract of price_contracts) {
    verify_price_contract_signature(contract)
  }
}

/**
 * Verify all oracles in the price contracts are authorized in the protocol.
 */
export function verify_price_oracles_authorized (vault_ctx : VaultRequestCtx<VaultBaseRequestConfig>) {
  const { price_contracts, proto_profile } = vault_ctx
  // If no price contracts, skip.
  if (!price_contracts || price_contracts.length === 0) return
  // Extract oracle pubkeys from the contracts.
  const oracle_pubkeys = price_contracts.map(c => c.oracle_pubkey)
  // Verify all oracles are authorized.
  verify_oracles_authorized(oracle_pubkeys, proto_profile)
}

export function verify_price_contract_data (vault_ctx : VaultRequestCtx<VaultBaseRequestConfig>) {
  // Unpack the vault context.
  const { price_commits, price_contracts, price_stamp, unit_balance } = vault_ctx
  // If the unit balance is zero, skip.
  if (unit_balance === 0) return
  // If the price contracts are not set, throw an error.
  if (!price_contracts || price_contracts.length === 0) {
    throw new Error('price contracts are missing from the vault context')
  }
  // Assert that the price stamp and price commits exist.
  Assert.exists(price_stamp,    'price stamp is missing from the vault context')
  Assert.exists(price_commits, 'price commits are missing from the vault context')
}

export function verify_collateral_ratio (vault_ctx : VaultRequestCtx<VaultBaseRequestConfig>) {
  // Unpack the vault context.
  const { price_commits, proto_profile, unit_balance, vault_balance, vault_terms } = vault_ctx
  const { vault_ratio_min } = vault_terms
  // Select the base price commit.
  const base_commit = select_base_price_commit(price_commits)
  Assert.exists(base_commit, 'base commit is missing from price commits')
  // Trust-boundary: adjust price into base-units-per-BTC for the math below.
  const adjusted_price = get_adjusted_commit_price(proto_profile, base_commit)
  // Calculate the collateral ratio of the vault action.
  const collateral_ratio = calc_collateral_ratio(vault_balance, unit_balance, adjusted_price)
  // Assert that the collateral ratio is greater than or equal to the protocol minimum.
  Assert.ok(collateral_ratio >= vault_ratio_min, `vault collateral ratio is below protocol minimum: ${collateral_ratio} < ${vault_ratio_min}`)
}

/**
 * Verify PSBT output amounts match expected values from vault context.
 * Detects if the PSBT was modified during the signing pipeline.
 *
 * @param pdata - The signed PSBT to verify
 * @param expected_amounts - Array of expected output amounts (BigInt)
 * @throws Error if any output amount doesn't match
 */
export function verify_psbt_output_integrity (
  pdata            : PSBTData,
  expected_amounts : bigint[]
) : void {
  Assert.ok(
    pdata.outputsLength === expected_amounts.length,
    `PSBT output count mismatch: expected ${expected_amounts.length}, got ${pdata.outputsLength}`
  )
  for (let idx = 0; idx < expected_amounts.length; idx++) {
    const vout = pdata.getOutput(idx)
    Assert.exists(vout.amount, `amount not set for vout index: ${idx}`)
    Assert.ok(
      vout.amount === expected_amounts[idx],
      `PSBT output ${idx} amount mismatch: expected ${expected_amounts[idx]}, got ${vout.amount}`
    )
  }
}

export interface VerifyPsbtOptions {
  /** Optional asset TX for package relay verification */
  asset_pdata?         : PSBTData
  /** If true, high fee rate errors become warnings instead of throwing */
  warn_only_high_fees? : boolean
  /**
   * Fractional under-estimate to tolerate on the LOW side before rejecting
   * (e.g. 0.05 accepts an effective rate down to 95% of target). Clamped to
   * `[0, FEERATE_TOLERANCE]` in verify; default 0 = strict (always throw below
   * target). A within-tolerance shortfall is downgraded to an observe warning.
   * Bounded replacement for the F20-removed `warn_only_low_fees` boolean — the
   * cap means a sub-target fee can never be accepted below
   * `txfee_rate * (1 - FEERATE_TOLERANCE)`.
   */
  low_feerate_tolerance? : number
  /**
   * Observe context for routing fee-rate warnings through the structured
   * observe layer. Threaded from the caller's `vault_ctx.observe`. When
   * omitted, fee-rate warnings are suppressed (errors still throw).
   */
  observe?             : ObserveContext
}

export function verify_vault_request_psbt (
  vault_pdata : PSBTData,
  txfee_rate  : number,
  options?    : VerifyPsbtOptions
) {
  const { asset_pdata, warn_only_high_fees = false, low_feerate_tolerance = 0, observe } = options ?? {}
  // Initialize the total input and output values using BigInt for precision safety.
  let txin_total = BigInt(0)
  let vout_total = BigInt(0)
  let sig_count  = 0

  // Iterate over the outputs in the PSBT.
  for (let idx = 0; idx < vault_pdata.outputsLength; idx++) {
    const vout = vault_pdata.getOutput(idx)
    // Assert that the amount and script key exist.
    Assert.exists(vout.amount, `amount not set for vout index: ${idx}`)
    Assert.exists(vout.script, `script key does not exist for vout index: ${idx}`)

    // Validate script has at least one byte before accessing.
    Assert.ok(vout.script.length > 0, `script is empty for vout index: ${idx}`)
    const script_code = vout.script[0]

    // Assert that the script code is valid.
    Assert.ok(OUTPUT_CODES.includes(script_code), `invalid script code: ${script_code}`)

    // If the script code is an OP_RETURN,
    if (script_code === OP_RETURN_CODE) {
      // Assert that the amount is zero.
      Assert.ok(vout.amount === BIGINT._0, `OP_RETURN output amount is not zero: ${vout.amount}`)
    } else {
      // Assert that the amount is not below the dust limit.
      Assert.ok(vout.amount >= BigInt(DUST_LIMIT), `amount is below the dust limit: ${vout.amount} < ${DUST_LIMIT}`)
      // Add the amount to the total output value.
      vout_total += vout.amount
    }
  }

  // Iterate over the inputs in the PSBT.
  for (let idx = 0; idx < vault_pdata.inputsLength; idx++) {
    // Fetch the input.
    const txin = vault_pdata.getInput(idx)
    // Assert that the non-witness UTXO is not set.
    Assert.ok(txin.nonWitnessUtxo === undefined, `legacy UTXO is not supported`)
    // Fetch the amount from the witness UTXO
    const amount = txin.witnessUtxo?.amount
    // Assert that the witness UTXO or non-witness UTXO exists.
    Assert.exists(amount, `prevout does not exist for txin index: ${idx}`)
    // Assert that the amount exists.
    Assert.exists(txin.witnessUtxo?.amount, `amount not set for txin index: ${idx}`)
    // Add the amount to the total input value.
    txin_total += amount
    // If the input does not have a sequence field, skip.
    if (!txin.sequence) continue
    // Decode the sequence data.
    const seq_data = decode_sequence(txin.sequence)
    // If the sequence data does not contain metadata, skip.
    if (seq_data.type !== 'metadata') continue
    // If the input is a type that requires a guardian signature,
    if (SIGOPS_CODES.includes(seq_data.code)) {
      // Increment the sig counter.
      sig_count++
    }
  }

  // Assert that the total input value is greater than or equal to the total output value.
  Assert.ok(txin_total >= vout_total, `spending inputs do not cover outputs: ${txin_total} < ${vout_total}`)
  // Calculate the total fees (in BigInt).
  const txfees_bigint = txin_total - vout_total

  // If the fee rate is zero,
  if (txfee_rate === 0) {
    // Assert that the total fees are zero.
    Assert.ok(txfees_bigint === BigInt(0), `fees are being paid on a zero fee transaction: ${txfees_bigint}`)
  } else {
    // Verify fees can safely be converted to Number for rate calculations.
    // Bitcoin total supply (~21M BTC = 2.1e15 sats) is well under MAX_SAFE_INTEGER (9e15).
    Assert.ok(txfees_bigint <= BIGINT._MAX, `fees exceed safe integer range: ${txfees_bigint}`)
    const txfees = Number(txfees_bigint)

    // Calculate the vault transaction size.
    const txsize = get_txsize(vault_pdata.hex)
    // Calculate the issue TX vsize for package relay (if provided).
    // For two-TX actions, miners evaluate fee rate based on combined package vsize.
    const issue_vsize = asset_pdata ? get_txsize(asset_pdata.hex).vsize : 0
    // Calculate the effective tx size / feerate (shared with quote path).
    const eff_txsize  = get_effective_vsize({
      tx_vsize      : txsize.vsize,
      sigops_count  : sig_count,
      package_vsize : issue_vsize
    })
    const eff_feerate = get_effective_feerate(txfees, {
      tx_vsize      : txsize.vsize,
      sigops_count  : sig_count,
      package_vsize : issue_vsize
    })
    const sigops_vsize = eff_txsize - txsize.vsize - issue_vsize

    // Compare against the tolerance-adjusted floor. With the default tolerance
    // of 0 this floor is exactly `txfee_rate`, so the reject path below is
    // byte-for-byte the strict (Codex F20) behavior. A within-margin shortfall
    // is downgraded to an observe warning — the bounded restoration of the
    // F20-removed bypass: `get_min_feerate` clamps the tolerance to
    // `[0, FEERATE_TOLERANCE]`, so a sub-target fee can never be accepted below
    // `txfee_rate * (1 - FEERATE_TOLERANCE)`.
    const min_feerate = get_min_feerate(txfee_rate, low_feerate_tolerance)
    if (eff_feerate < min_feerate) {
      const pkg_info = asset_pdata ? `, issue_vsize=${issue_vsize}` : ''
      throw new Error(`effective fee rate is below the expected fee rate: ${eff_feerate.toFixed(2)} < ${txfee_rate} (vsize=${txsize.vsize}, sigops_vsize=${sigops_vsize}${pkg_info}, fees=${txfees})`)
    } else if (eff_feerate < txfee_rate) {
      const pkg_info = asset_pdata ? `, issue_vsize=${issue_vsize}` : ''
      const message  = `effective fee rate is below target but within tolerance: ${eff_feerate.toFixed(2)} < ${txfee_rate} (vsize=${txsize.vsize}, sigops_vsize=${sigops_vsize}${pkg_info}, fees=${txfees})`
      if (observe) emit_warn(observe, 'verify.feerate', message, { eff_feerate, min_feerate, txfee_rate })
    }

    // Calculate thresholds for high fee rate validation
    const warn_feerate  = txfee_rate * FEERATE_WARN_MULTIPLIER
    const error_feerate = txfee_rate * FEERATE_ERROR_MULTIPLIER

    // If the effective feerate exceeds error threshold, throw (or warn if configured)
    if (eff_feerate > error_feerate) {
      const pkg_info = asset_pdata ? `, issue_vsize=${issue_vsize}` : ''
      const message  = `effective fee rate exceeds error threshold: ${eff_feerate.toFixed(2)} > ${error_feerate.toFixed(2)} (${FEERATE_ERROR_MULTIPLIER}x expected) (vsize=${txsize.vsize}, sigops_vsize=${sigops_vsize}${pkg_info}, fees=${txfees})`
      if (warn_only_high_fees) {
        if (observe) emit_warn(observe, 'verify.feerate', message, { eff_feerate, threshold: error_feerate })
      } else {
        throw new Error(message)
      }
    }
    // If the effective feerate exceeds warning threshold, warn
    else if (eff_feerate > warn_feerate) {
      const pkg_info = asset_pdata ? `, issue_vsize=${issue_vsize}` : ''
      const message  = `effective fee rate exceeds warning threshold: ${eff_feerate.toFixed(2)} > ${warn_feerate.toFixed(2)} (${FEERATE_WARN_MULTIPLIER}x expected) (vsize=${txsize.vsize}, sigops_vsize=${sigops_vsize}${pkg_info}, fees=${txfees})`
      if (observe) emit_warn(observe, 'verify.feerate', message, { eff_feerate, threshold: warn_feerate })
    }
  }
}

/**
 * Verify reserve payout calculation is correct.
 *
 * Step 5 of multi-vault liquidation verification:
 * - Calculates expected reserve from all liquidated vaults
 * - Reserve is only paid if above minimum threshold
 * - Verifies reserve_balance matches expected value
 *
 * Note: Reserve address verification happens at PSBT creation time
 * via create_reserve_spend_output() which uses vault_terms.reserve_pubkey
 *
 * @param vault_ctx - The vault request context for repo/trim
 * @throws Error if reserve payout calculation is incorrect
 */
function verify_reserve_payout (
  vault_ctx : VaultRequestCtx<VaultBaseRequestConfig>
) : void {
  const { liquid_profiles, reserve_balance, vault_terms } = vault_ctx

  // Calculate expected reserve from all liquidated vaults
  const total_reserve = (liquid_profiles ?? []).reduce(
    (sum, profile) => sum + profile.reserve_sats, 0
  )

  // Reserve is only paid if above minimum threshold
  const expected_reserve = (total_reserve >= vault_terms.reserve_sats_min)
    ? total_reserve
    : 0

  // Verify reserve balance calculation is consistent
  Assert.ok(
    reserve_balance === expected_reserve,
    `reserve payout mismatch: ${reserve_balance} !== ${expected_reserve}`
  )
}

/**
 * Verify the vault action rules using core-ts dispatcher.
 *
 * Builds a vault profile from the context and validates it against
 * protocol rules for the specific action type (open, borrow, repay, etc).
 *
 * For repo/trim actions, uses five-step multi-vault verification:
 * 1. Verify liquidator's vault transition (has vault, ratio ok)
 * 2. Verify each liquidated vault is eligible (underwater)
 * 3. Verify each liquidated vault transition via core-ts 'liquidate' action
 * 4. Verify liquidation amounts are internally consistent
 * 5. Verify reserve payout calculation is correct
 *
 * @param vault_ctx - The vault request context containing all action parameters.
 * @param vault_txid - The transaction ID of the vault transaction (used for root_txid on open).
 * @throws Error if the action violates any protocol rules.
 */
export function verify_vault_action_rules (
  vault_ctx  : VaultRequestCtx<VaultBaseRequestConfig>,
  vault_txid : string
) : void {
  const { vault_action } = vault_ctx

  // For repo/trim: Use five-step liquidation verification
  if (vault_action === 'repo' || vault_action === 'trim') {
    // Step 1: Verify liquidator's vault transition (has vault, ratio ok)
    verify_liquidator_vault_transition(vault_ctx)
    // Step 2: Verify each liquidated vault is eligible (underwater)
    verify_liquid_vaults_eligible(vault_ctx.liquid_profiles ?? [])
    // Step 3: Verify each liquidated vault transition via core-ts 'liquidate' action
    verify_liquid_vault_transitions(vault_ctx)
    // Step 4: Verify liquidation amounts are internally consistent
    verify_liquidation_amounts(vault_ctx)
    // Step 5: Verify reserve payout calculation is correct
    verify_reserve_payout(vault_ctx)
    return
  }

  // Unpack the vault context.
  const {
    client_pubkey,
    guard_members,
    guard_pubkey,
    price_commits,
    price_stamp,
    proto_profile,
    unit_balance,
    vault_balance,
    vault_config,
    vault_profile: prev_profile,
    vault_terms,
    vault_version
  } = vault_ctx

  // Calculate vault_ratio, unit_price, and thold_price from price commits.
  let vault_ratio : number | null = null
  let unit_price  : number | null = null
  let thold_price : number | null = null

  if (unit_balance > 0 && price_commits && price_commits.length > 0) {
    // Select the base price commit.
    const base_commit = select_base_price_commit(price_commits)
    if (base_commit) {
      // Trust-boundary: adjust price into base-units-per-BTC.
      const adjusted_price = get_adjusted_commit_price(proto_profile, base_commit)
      // Calculate the collateral ratio.
      vault_ratio = calc_collateral_ratio(vault_balance, unit_balance, adjusted_price)
      // Extract prices from base commit.
      unit_price  = base_commit.base_price
      thold_price = base_commit.thold_price
    }
  }

  // Build the new vault profile from context. coin_id and vault_script are
  // not yet known at request-construction time (the vault tx isn't finalized),
  // so they are null here. The schema treats both as nullable; the action
  // verifiers (incl. verify_vault_profile) validate balances, ratios, and
  // price commits, not the outpoint/script. An empty string is NOT valid for
  // coin_id (it must match the txid:vout outpoint pattern), so null is required.
  const new_profile : VaultProfile = {
    // VaultSequenceData
    vault_action,
    vault_version,
    // VaultReturnData
    guard_members,
    price_commits  : price_commits ?? [],
    price_stamp    : price_stamp ?? null,
    unit_balance,
    unit_price,
    thold_price,
    // VaultProfile additional fields
    coin_id        : null,
    client_pubkey,
    contract_id    : proto_profile.contract_id,
    guard_pubkey,
    root_txid      : prev_profile?.root_txid ?? vault_txid,
    vault_balance,
    vault_config   : vault_config ?? null,
    vault_ratio,
    vault_script   : null,
    vault_value    : (vault_action === 'close')
      ? null
      : (vault_balance + vault_terms.vault_value_min)
  }

  // Dispatch on the action to the matching dedicated core verifier.
  // repo/trim are handled earlier (multi-vault path); liquidate is internal
  // to that path and never reaches here.
  switch (vault_action) {
    case 'open':
      Assert.ok(prev_profile == null, 'open action must not have a previous profile')
      verify_vault_open_strict(proto_profile, new_profile)
      reject_on_policy_flags('verify_vault_open', eval_vault_open_policy(proto_profile, new_profile))
      break
    case 'borrow':
      Assert.exists(prev_profile, 'borrow action requires a previous profile')
      verify_vault_borrow_strict(proto_profile, new_profile, prev_profile)
      reject_on_policy_flags('verify_vault_borrow', eval_vault_borrow_policy(proto_profile, new_profile, prev_profile))
      break
    case 'repay':
      Assert.exists(prev_profile, 'repay action requires a previous profile')
      verify_vault_repay_strict(proto_profile, new_profile, prev_profile)
      reject_on_policy_flags('verify_vault_repay', eval_vault_repay_policy(proto_profile, new_profile, prev_profile))
      break
    case 'deposit':
      Assert.exists(prev_profile, 'deposit action requires a previous profile')
      verify_vault_deposit(proto_profile, new_profile, prev_profile)
      break
    case 'withdraw':
      Assert.exists(prev_profile, 'withdraw action requires a previous profile')
      verify_vault_withdraw_strict(proto_profile, new_profile, prev_profile)
      reject_on_policy_flags('verify_vault_withdraw', eval_vault_withdraw_policy(proto_profile, new_profile, prev_profile))
      break
    case 'close':
      Assert.exists(prev_profile, 'close action requires a previous profile')
      verify_vault_close(proto_profile, new_profile, prev_profile)
      break
    default:
      throw new Error(`unknown vault action: ${vault_action}`)
  }
}
