/**
 * @fileoverview Guardian client for WebSocket communication.
 *
 * The GuardianClient provides a high-level interface for communicating with
 * guardian nodes in the DUCAT protocol. Guardians are responsible for:
 *
 * 1. **Co-signing vault transactions**: All vault state changes (open, deposit,
 *    borrow, repay, close, withdraw) require guardian co-signatures via Taproot scripts.
 *    This ensures the MPC group validates each transaction before it can be spent.
 *
 * 2. **Validating price commits**: Guardians verify oracle price signatures
 *    to ensure collateral ratios are calculated correctly.
 *
 * 3. **Processing liquidations**: When vaults become under-collateralized,
 *    guardians can sign liquidation transactions (repo/trim actions).
 *
 * ## Communication Flow
 *
 * ```
 * Client                    Guardian
 *   |                          |
 *   |--- WebSocket Connect --->|
 *   |                          |
 *   |--- Vault Request ------->|  (signed PSBT + metadata)
 *   |                          |  Guardian validates:
 *   |                          |  - Price commits are valid
 *   |                          |  - Collateral ratio is sufficient
 *   |                          |  - Transaction structure is correct
 *   |<-- Co-signed PSBT -------|  (or rejection with reason)
 *   |                          |
 * ```
 *
 * ## Usage Example
 *
 * ```typescript
 * const client = new GuardianClient('wss://guardian.example.com', 'mainnet')
 *
 * // Submit a vault open request
 * const response = await client.request.vault.open(openRequest)
 *
 * // Close when done
 * client.close()
 * ```
 */

import { WebSocketClient }           from '@/class/socket.js'
import { child_observe_context }     from '@/lib/observe/index.js'
import { get_observe_context }       from '@/lib/observe/index.js'
import { reserve_asset_account_api } from '@/module/guard/api/asset/reserve.js'
import * as VAULT_API                from '@/module/guard/api/vault/index.js'
import type { ChainNetwork }         from '@ducat-unit/core'
import type {
  ObserveContext,
  ObservabilityOptions
} from '@/lib/observe/index.js'

export interface GuardianClientOptions {
  allow_insecure_ws? : boolean
  observability? : ObservabilityOptions | ObserveContext
}

/**
 * WebSocket client for communicating with DUCAT guardian nodes.
 *
 * Provides request APIs for all vault operations that require guardian
 * co-signatures. Each request sends a signed PSBT to the guardian, which
 * validates the transaction and returns a co-signed PSBT or rejection.
 */
export class GuardianClient {
  private readonly _network : ChainNetwork
  private readonly _observe : ObserveContext
  private readonly _socket  : WebSocketClient

  /**
   * Creates a new GuardianClient connection.
   *
   * @param host_url - WebSocket URL of the guardian node (e.g., 'wss://guardian.example.com')
   * @param network - Bitcoin network to operate on ('mainnet', 'testnet', 'regtest')
   */
  constructor (
    host_url : string,
    network  : ChainNetwork,
    options  : GuardianClientOptions = {}
  ) {
    this._network = network
    this._observe = get_observe_context(options.observability, {
      module  : 'guardian',
      network
    })
    this._socket  = new WebSocketClient(host_url, {
      allow_insecure_ws : options.allow_insecure_ws,
      observability : child_observe_context(this.observe, {
        module     : 'guardian_socket',
        network,
        socket_url : host_url
      })
    })
  }

  /** The Bitcoin network this client is configured for. */
  get network () {
    return this._network
  }

  get observe () {
    return this._observe
  }

  /**
   * Request APIs for guardian operations.
   *
   * - `asset.reserve`: Reserve an asset account for receiving UNIT
   * - `vault.open`: Open a new vault with initial deposit and borrow
   * - `vault.deposit`: Add more BTC collateral to an existing vault
   * - `vault.borrow`: Borrow additional UNIT against collateral
 * - `vault.repay`: Pay back borrowed UNIT
 * - `vault.close`: Close a cleared vault and withdraw all collateral
 * - `vault.withdraw`: Remove BTC collateral from vault
   * - `vault.repo`: Liquidate an under-collateralized vault
   * - `vault.trim`: Partial liquidation of a vault
   */
  get request () {
    return {
      asset : {
        reserve : reserve_asset_account_api(this)
      },
      vault : {
        borrow   : VAULT_API.borrow_vault_api(this),
        close    : VAULT_API.close_vault_api(this),
        deposit  : VAULT_API.deposit_vault_api(this),
        open     : VAULT_API.open_vault_api(this),
        repay    : VAULT_API.repay_vault_api(this),
        repo     : VAULT_API.repo_vault_api(this),
        trim     : VAULT_API.trim_vault_api(this),
        withdraw : VAULT_API.withdraw_vault_api(this)
      }
    }
  }

  /** The underlying WebSocket client for low-level operations. */
  get socket () {
    return this._socket
  }

  /** Closes the WebSocket connection to the guardian. */
  close () {
    this._socket.close()
  }
}
