/**
 * @fileoverview Wallet account derivation helpers for v0/v1 script formats.
 */

import { Buff }             from '@vbyte/buff'
import { hash160 }          from '@vbyte/crypto/hash'
import { P2TR, P2WPKH }     from '@vbyte/btc-dev/address'
import { ChainNetwork }     from '@ducat-unit/core'
import { derive_taproot_output_key, to_address_network } from '@ducat-unit/core/lib'
import { ValidationError }  from '@/lib/errors/index.js'

import {
  serialize_pubkey
} from '@vbyte/crypto/ecc'

import type {
  ProtoWalletAccountAPI,
  ProtoWalletAccountData,
  ProtoWalletAccount
} from '@/types/index.js'

/**
 * Derive wallet account bundle (asset, funds, vault) for a chain network.
 * @param config - Account pubkeys and witness versions.
 * @param network - Target chain network.
 * @returns Wallet account data keyed by role.
 */
export function get_wallet_accounts (
  config  : ProtoWalletAccountAPI,
  network : ChainNetwork
) : ProtoWalletAccountData {
  // Unpack the account configurations.
  const { asset, funds, vault } = config
  // Return the portfolio.
  return {
    asset : get_wallet_account(network, asset.pubkey, 1),
    funds : get_wallet_account(network, funds.pubkey, funds.version),
    vault : get_wallet_account(network, vault.pubkey, 1)
  }
}

/**
 * Get the account data for a given network, pubkey and version.
 * @param network - The chain network.
 * @param pubkey  - The pubkey.
 * @param version - The account version.
 * @returns The account data.
 */
function get_wallet_account (
  network : ChainNetwork,
  pubkey  : string,
  version : number
) : ProtoWalletAccount {
  // For the given version,
  switch (version) {
    case 0:
      // Return the v0 account data.  
      return get_v0_account_data(network, pubkey)
    case 1:
      // Return the v1 account data.
      return get_v1_account_data(network, pubkey)
    default:
      // Throw an error if the version is invalid.
      throw new ValidationError(`invalid account version: ${version}`)
  }
}

/**
 * Get the account data for witness version 0.
 * @param network - The chain network.
 * @param pubkey  - The pubkey.
 * @returns The v0 account data.
 */
function get_v0_account_data (
  network : ChainNetwork,
  pubkey  : string
) : ProtoWalletAccount {
  // Serialize the pubkey to ecdsa format.
  const _pubkey = serialize_pubkey(pubkey, 'ecdsa')
  // Return the account data.
  return {
    address : P2WPKH.create_address(_pubkey, to_address_network(network)),
    keydata : hash160(_pubkey).hex,
    pubkey  : _pubkey.hex,
    version : 0
  }
}

/**
 * Get the account data for witness version 1.
 * @param network - The chain network.
 * @param pubkey  - The pubkey.
 * @returns The v1 account data.
 */
function get_v1_account_data (
  network : ChainNetwork,
  pubkey  : string
) : ProtoWalletAccount {
  // Serialize the pubkey to bip340 format.
  const _pubkey = serialize_pubkey(pubkey, 'bip340')
  // Derive the final taproot output key from the internal key.
  const _tapkey = Buff.hex(derive_taproot_output_key(_pubkey.hex))
  // Return the account data.
  return {
    address : P2TR.create_address(_tapkey, to_address_network(network)),
    keydata : _tapkey.hex,
    pubkey  : _pubkey.hex,
    version : 0x51
  }
}
