/**
 * @fileoverview Zod schemas for vault action request payloads.
 *
 * All `*_amount`, `*_balance`, `claimed_*`, and `unit_*` numeric fields in
 * these schemas are in smallest-divisible base units of the relevant asset
 * (per `asset_profile.div`). Display-unit conversion is the responsibility of
 * presentation-layer code only. See `dev/docs/CONVENTIONS.md#unit-convention`.
 */

import { z } from 'zod'

import { base, chain, vault } from '@ducat-unit/core/schema'

import type {
  VaultBorrowRequest,
  VaultDepositRequest,
  VaultCloseRequest,
  VaultOpenRequest,
  VaultRepayRequest,
  VaultRepoRequest,
  VaultBaseRequest,
  VaultWithdrawRequest,
  VaultTrimRequest
} from '@ducat-unit/core'

const base_request = z.object({
  borrow_amount   : base.uint.optional(),
  chain_network   : chain.network,
  change_amount   : base.uint.optional(),
  client_pubkey   : base.hex32,
  deposit_amount  : base.uint.optional(),
  guard_members   : base.hex32.array(),
  guard_pubkey    : base.hex32,
  contract_id     : base.hex32,
  root_txid       : base.hex32.optional(),
  sighashes       : z.object({
    idx     : base.uint,
    sighash : base.hex32,
    sigflag : base.uint
  }).array().optional(),
  vault_action    : vault.action,
  vault_config    : vault.config.optional(),
  withdraw_amount : base.uint.optional(),
}) satisfies z.ZodType<VaultBaseRequest>

export const vault_open = z.object({
  ...base_request.shape,
  borrow_amount  : base.uint,
  deposit_amount : base.uint,
  issue_psbt     : base.base64,
  issue_txid     : base.hex32,
  vault_psbt     : base.base64,
  vault_txid     : base.hex32,
}) satisfies z.ZodType<VaultOpenRequest>

export const vault_borrow = z.object({
  ...base_request.shape,
  borrow_amount  : base.uint,
  issue_psbt     : base.base64,
  issue_txid     : base.hex32,
  root_txid      : base.hex32,
  vault_psbt     : base.base64,
  vault_txid     : base.hex32,
}) satisfies z.ZodType<VaultBorrowRequest>

export const vault_repay = z.object({
  ...base_request.shape,
  repay_amount : base.uint,
  burn_psbt    : base.base64,
  burn_txid    : base.hex32,
  root_txid    : base.hex32,
  vault_psbt   : base.base64,
  vault_txid   : base.hex32,
}) satisfies z.ZodType<VaultRepayRequest>

export const vault_repo = z.object({
  ...base_request.shape,
  vault_psbt   : base.base64,
  vault_txid   : base.hex32,
}) satisfies z.ZodType<VaultRepoRequest>

export const vault_trim = z.object({
  ...base_request.shape,
  vault_psbt   : base.base64,
  vault_txid   : base.hex32,
}) satisfies z.ZodType<VaultTrimRequest>

export const vault_deposit = z.object({
  ...base_request.shape,
  deposit_amount : base.uint,
  root_txid      : base.hex32,
  vault_psbt     : base.base64,
  vault_txid     : base.hex32,
}) satisfies z.ZodType<VaultDepositRequest>

export const vault_withdraw = z.object({
  ...base_request.shape,
  root_txid       : base.hex32,
  vault_psbt      : base.base64,
  vault_txid      : base.hex32,
  withdraw_amount : base.uint
}) satisfies z.ZodType<VaultWithdrawRequest>

export const vault_close = z.object({
  ...base_request.shape,
  root_txid   : base.hex32,
  vault_psbt  : base.base64,
  vault_txid  : base.hex32
}) satisfies z.ZodType<VaultCloseRequest>
