/**
 * @fileoverview Validator API fetch helpers for latest and historical price contracts.
 */

import { Fetch, Resolve }          from '@vbyte/util'
import {
  validate_fetch_list_response,
  validate_fetch_response
} from './util.js'
import * as SHARED                 from '@ducat-unit/core/schema'

import type { PriceContract } from '@ducat-unit/core'

/**
 * Fetches the latest price contracts from the validator API
 * @param host_url - Base URL of the validator API server
 * @returns Array of price contract data or error response
 */
export async function fetch_price_latest (
  host_url : string
) : Promise<Resolve.Type<PriceContract[]>> {
  const url = `${host_url}/api/price/latest`
  const res = await Fetch.json(url)
  if (!res.ok) return res
  return validate_fetch_response(
    SHARED.price.contract.array(),
    res.data,
    'price latest validation failed'
  )
}

/**
 * Fetches price contract history from the validator API
 * @param host_url - Base URL of the validator API server
 * @param page_size - Maximum number of records to return
 * @param cursor   - Opaque cursor for the next page
 * @param breached - Filter by breached status
 * @returns Array of price contract data or error response
 */
export async function fetch_price_history (
  host_url  : string,
  page_size?  : number,
  cursor?   : string,
  breached? : boolean
) : Promise<Resolve.Type<PriceContract[]>> {
  const url = new URL(`${host_url}/api/price/history`)
  if (page_size !== undefined) url.searchParams.set('page_size', String(page_size))
  if (cursor   !== undefined) url.searchParams.set('cursor', cursor)
  if (breached !== undefined) url.searchParams.set('breached', String(breached))
  const res = await Fetch.json(url.toString())
  if (!res.ok) return res
  return validate_fetch_list_response(
    SHARED.price.contract.array(),
    res.data,
    'price history validation failed'
  )
}
