/**
 * @fileoverview OpenTelemetry-backed tracer adapter.
 *
 * The adapter only depends on @opentelemetry/api. The host application
 * installs the OTel SDK, exporters, and provider; this module is a no-op
 * when no provider is registered.
 */

import {
  context as otel_context,
  SpanStatusCode,
  trace
} from '@opentelemetry/api'

import type {
  Attributes,
  AttributeValue,
  Span as OtelSpan,
  Tracer as OtelTracer
} from '@opentelemetry/api'

import { redact_observe_fields } from './redact.js'

import type {
  SdkTracer,
  TraceSpan
} from './types.js'

const DEFAULT_INSTRUMENTATION_NAME = 'ducat-client-sdk'

const OTEL_SPAN = Symbol('observe.otel_span')

// Bound the error text that reaches the telemetry backend. Error
// messages in this SDK routinely embed PSBTs, sighashes, and
// addresses; an unbounded copy leaks them wholesale (Codex F30).
const MAX_ERROR_MESSAGE_LENGTH = 256

function truncate_error_message (message : string) : string {
  if (message.length <= MAX_ERROR_MESSAGE_LENGTH) return message
  const omitted = message.length - MAX_ERROR_MESSAGE_LENGTH
  return `${message.slice(0, MAX_ERROR_MESSAGE_LENGTH)}… [truncated ${omitted} chars]`
}

interface OtelBackedSpan extends TraceSpan {
  readonly [OTEL_SPAN] : OtelSpan
}

export interface OtelTracerAdapterOptions {
  instrumentation_name?    : string
  instrumentation_version? : string
  redact_sensitive?        : boolean
  unsafe_payloads?         : boolean
}

function is_otel_backed (span : TraceSpan | undefined) : span is OtelBackedSpan {
  return span !== undefined && OTEL_SPAN in span
}

function coerce_attribute_value (value : unknown) : AttributeValue | undefined {
  if (value === null || value === undefined) return undefined
  const t = typeof value
  if (t === 'string' || t === 'number' || t === 'boolean') {
    return value as AttributeValue
  }
  if (Array.isArray(value)) {
    const head = value.find(v => v !== null && v !== undefined)
    const head_t = typeof head
    if (head_t === 'string' || head_t === 'number' || head_t === 'boolean') {
      return value as AttributeValue
    }
    return JSON.stringify(value)
  }
  try {
    return JSON.stringify(value)
  } catch {
    return String(value)
  }
}

function to_otel_attributes (
  fields : Record<string, unknown>
) : Attributes {
  const attrs : Attributes = {}
  for (const [ key, value ] of Object.entries(fields)) {
    const coerced = coerce_attribute_value(value)
    if (coerced !== undefined) attrs[key] = coerced
  }
  return attrs
}

export function create_otel_tracer_adapter (
  options : OtelTracerAdapterOptions = {}
) : SdkTracer {
  const redact_sensitive = options.redact_sensitive ?? true
  const unsafe_payloads  = options.unsafe_payloads  ?? false
  const tracer : OtelTracer = trace.getTracer(
    options.instrumentation_name ?? DEFAULT_INSTRUMENTATION_NAME,
    options.instrumentation_version
  )

  function redact (fields : Record<string, unknown>) {
    return redact_observe_fields(fields, redact_sensitive, unsafe_payloads)
  }

  return {
    start_span (name, fields = {}, parent) {
      const safe_fields  = redact(fields)
      const attributes   = to_otel_attributes(safe_fields)
      const parent_ctx   = is_otel_backed(parent)
        ? trace.setSpan(otel_context.active(), parent[OTEL_SPAN])
        : otel_context.active()
      const otel_span    = tracer.startSpan(name, { attributes }, parent_ctx)
      const sc           = otel_span.spanContext()
      const span : OtelBackedSpan = {
        [OTEL_SPAN]    : otel_span,
        trace_id       : sc.traceId,
        span_id        : sc.spanId,
        parent_span_id : parent?.span_id,
        event (event_name, event_fields = {}) {
          const safe = redact(event_fields)
          otel_span.addEvent(event_name, to_otel_attributes(safe))
        },
        end (end_fields = {}) {
          const safe = redact(end_fields)
          if (Object.keys(safe).length > 0) {
            otel_span.setAttributes(to_otel_attributes(safe))
          }
          otel_span.end()
        },
        fail (error, fail_fields = {}) {
          const safe = redact(fail_fields)
          if (Object.keys(safe).length > 0) {
            otel_span.setAttributes(to_otel_attributes(safe))
          }
          const name        = (error instanceof Error) ? error.name : 'Error'
          const raw_message = (error instanceof Error) ? error.message : String(error)
          if (redact_sensitive) {
            // Record a sanitized exception only. Passing the raw Error
            // to recordException would capture its full message AND
            // stack — both routinely contain PSBTs/sighashes/addresses
            // (Codex F30). Truncate to bound the leak surface and omit
            // the stack entirely.
            const message = truncate_error_message(raw_message)
            otel_span.recordException({ name, message })
            otel_span.setStatus({ code: SpanStatusCode.ERROR, message })
          } else {
            // Explicit opt-out (redact_sensitive: false): capture the
            // full error for local debugging.
            if (error instanceof Error) {
              otel_span.recordException(error)
            } else {
              otel_span.recordException({ name, message: raw_message })
            }
            otel_span.setStatus({ code: SpanStatusCode.ERROR, message: raw_message })
          }
          otel_span.end()
        }
      }
      return span
    }
  }
}
