export class ValidationError extends Error {
    constructor(message) {
        super(message);
        this.name = 'ValidationError';
    }
}
export class HexValidationError extends ValidationError {
    constructor(message) {
        super(message);
        this.name = 'HexValidationError';
    }
}
export class ByteRangeError extends ValidationError {
    constructor(message) {
        super(message);
        this.name = 'ByteRangeError';
    }
}
export class IntegerBoundsError extends ValidationError {
    constructor(message) {
        super(message);
        this.name = 'IntegerBoundsError';
    }
}
export class SizeError extends ValidationError {
    constructor(message) {
        super(message);
        this.name = 'SizeError';
    }
}
