/**
 * @fileoverview Shared effective-size and feerate calculations.
 */

import { get_sigops_vsize } from './calc.js'
import { FEERATE_TOLERANCE } from '@/const.js'

export interface EffectiveSizeConfig {
  tx_vsize      : number
  sigops_count  : number
  package_vsize? : number
}

/** Calculate effective vsize used for policy feerate checks. */
export function get_effective_vsize (config : EffectiveSizeConfig) : number {
  const { tx_vsize, sigops_count, package_vsize = 0 } = config
  const sigops_vsize = get_sigops_vsize(sigops_count)
  return tx_vsize + sigops_vsize + package_vsize
}

/** Calculate effective feerate from fees and size policy inputs. */
export function get_effective_feerate (
  fees   : number,
  config : EffectiveSizeConfig
) : number {
  return fees / get_effective_vsize(config)
}

/**
 * Minimum acceptable effective feerate for a target rate, given an optional
 * low-side tolerance. The tolerance is clamped to `[0, FEERATE_TOLERANCE]` (the
 * hard cap), so callers — including untrusted request configs — can never lower
 * the floor below `txfee_rate * (1 - FEERATE_TOLERANCE)`. With the default
 * tolerance of 0 the floor is exactly `txfee_rate` (strict).
 *
 * @param txfee_rate - The target fee rate (sats/vByte).
 * @param tolerance  - Fractional under-estimate to allow (default 0).
 * @returns The minimum effective feerate that should be accepted.
 */
export function get_min_feerate (txfee_rate : number, tolerance = 0) : number {
  const clamped = Math.min(Math.max(tolerance, 0), FEERATE_TOLERANCE)
  return txfee_rate * (1 - clamped)
}
