/**
 * @fileoverview Vault repossession output builders.
 */

import { Buff }               from '@vbyte/buff'
import { Assert }             from '@vbyte/util'
import { DUST_LIMIT }         from '@ducat-unit/core/const'
import { derive_p2tr_script } from '@ducat-unit/core/lib'

import { create_taproot_script_key } from '../util.js'

import {
  create_cleared_vault_script_tree,
  create_pledged_vault_script_tree
} from '../vault/script.js'

import type {
  PSBTOutput,
  VaultProfile
} from '@ducat-unit/core'

import type { VaultRequestCtx } from '@/types/index.js'

/**
 * Create the next vault output for a pledged (price-commit locked) vault state.
 * @param vault_profile - Vault profile used to derive pledged tree scripts.
 * @param vault_amount - Output amount in satoshis.
 * @returns PSBT output paying to the pledged vault Taproot script.
 */
export function create_liquid_vault_locked_output (
  vault_profile : VaultProfile,
  vault_amount  : number
) : PSBTOutput {
  // Unpack the vault profile.
  const { client_pubkey, price_commits, guard_members } = vault_profile
  // Assert that the thold hashes are defined.
  Assert.exists(price_commits, 'price commits are missing from vault profile')
  // Create the bitcoin script for the vault utxo.
  const scripts = create_pledged_vault_script_tree(client_pubkey, guard_members, price_commits)
  // Create the taproot script.
  const script_pk = create_taproot_script_key(scripts)
  // Return the vault output.
  return { amount: BigInt(vault_amount), script: script_pk }
}

/**
 * Create the next vault output for a cleared (unit-balance zero) vault state.
 * @param vault_profile - Vault profile used to derive cleared tree scripts.
 * @param vault_amount - Output amount in satoshis.
 * @returns PSBT output paying to the cleared vault Taproot script.
 */
export function create_liquid_vault_cleared_output (
  vault_profile : VaultProfile,
  vault_amount  : number
) : PSBTOutput {
  // Unpack the vault profile.
  const { client_pubkey, guard_members } = vault_profile
  // Create the bitcoin script for the vault utxo.
  const scripts   = create_cleared_vault_script_tree(client_pubkey, guard_members)
  // Create the taproot script.
  const script_pk = create_taproot_script_key(scripts)
  // Return the vault output.
  return { amount: BigInt(vault_amount), script: script_pk }
}

/**
 * Create the reserve payout output for repossession settlement.
 * @param vault_ctx - Request context containing reserve terms.
 * @param reserve_amount - Reserve payout amount in satoshis.
 * @returns PSBT output paying the reserve key-path address.
 */
export function create_reserve_spend_output (
  vault_ctx      : VaultRequestCtx,
  reserve_amount : number
) : PSBTOutput {
  // Define the reserve pubkey.
  const reserve_pubkey = vault_ctx.vault_terms.reserve_pubkey
  // Assert the reserve amount is at least the dust limit.
  Assert.ok(reserve_amount >= DUST_LIMIT, `reserve amount is below dust limit (${DUST_LIMIT})`)
  Assert.is_hash(reserve_pubkey,         'reserve pubkey is invalid')
  // Create the bitcoin script for the change output.
  const script = Buff.hex(derive_p2tr_script(reserve_pubkey))
  // Return the change output.
  return { amount: BigInt(reserve_amount), script }
}
