/**
 * @fileoverview Asset-id helpers for the SDK.
 */

import { get_vault_terms } from '@ducat-unit/core/lib'

import type { ProtoProfile } from '@ducat-unit/core'

/**
 * Get the unit asset ID from the proto profile.
 *
 * @param proto_profile - The proto profile.
 * @returns The unit asset ID.
 */
export function get_unit_asset_id (
  proto_profile : ProtoProfile
) : string {
  // Get the vault terms.
  const vault_terms = get_vault_terms(proto_profile.proto_terms)
  // Return the unit asset ID.
  return vault_terms.unit_asset_id
}
