/**
 * @fileoverview Formatting helpers for Zod validation error messages.
 */

import type { ZodError } from 'zod'

/**
 * Formats Zod error issues into an array of human-readable strings.
 * @param zod_error - The Zod validation error
 * @returns Array of formatted error messages
 */
export function format_zod_errors (zod_error: ZodError): string[] {
  return zod_error.issues.map(issue => {
    const path = issue.path.length > 0 ? issue.path.join('.') : 'root'
    return `${path}: ${issue.message}`
  })
}

/**
 * Creates a formatted error message from Zod errors with optional prefix.
 * @param zod_error    - The Zod validation error
 * @param error_prefix - Optional prefix for the error message
 * @returns Formatted error message string
 */
export function format_validation_message (
  zod_error    : ZodError,
  error_prefix?: string
): string {
  const details = format_zod_errors(zod_error)
  const prefix  = error_prefix ?? 'validation failed'
  return `${prefix}: ${details.join(', ')}`
}
