/**
 * @fileoverview Multi-vault liquidation verification utilities.
 *
 * Provides the step-wise verification cluster used by repo/trim actions to
 * validate liquidation of one or more underwater vaults:
 * - Verifying the liquidator's own vault transition (collateral ratio holds)
 * - Verifying each liquidated vault is eligible (encumbered + underwater)
 * - Verifying each liquidated vault transition via the core 'liquidate' action
 * - Verifying liquidation amounts are internally consistent
 *
 * These functions are consumed by `verify_vault_action_rules` in
 * `./verify.js`, which orchestrates the full multi-vault liquidation flow.
 *
 * @module vault/lib/verify_liquidation
 */

import { Assert } from '@vbyte/util'

import {
  convert_unit_to_sats,
  get_vault_profile_ratio,
  verify_vault_liquidate
} from '@ducat-unit/core/lib'

import { get_adjusted_liquid_price } from '@/lib/vault/util.js'

import { verify_collateral_ratio } from './verify.js'

import type { LiquidVaultProfile, VaultAction, VaultProfile } from '@ducat-unit/core'

import type {
  VaultBaseRequestConfig,
  VaultRequestCtx
} from '@/types/index.js'

/**
 * Verify the liquidator's vault transition for repo/trim.
 *
 * Step 1 of multi-vault liquidation verification:
 * - Verifies liquid_profiles exist (must have vaults to liquidate)
 * - Verifies liquidator has an existing vault (required for repo/trim)
 * - Verifies collateral ratio still meets minimum after taking debt
 *
 * @param vault_ctx - The vault request context for repo/trim
 * @throws Error if liquidator vault transition is invalid
 */
export function verify_liquidator_vault_transition (
  vault_ctx : VaultRequestCtx<VaultBaseRequestConfig>
) : void {
  const { liquid_profiles, vault_profile: prev_profile, unit_balance } = vault_ctx

  // Must have at least one vault to liquidate
  Assert.ok(
    liquid_profiles && liquid_profiles.length > 0,
    'repo/trim requires at least one liquid profile'
  )

  // Liquidator must have an existing vault
  Assert.exists(
    prev_profile,
    'repo/trim requires liquidator to have an existing vault'
  )

  // After taking on debt from liquidated vaults, verify collateral ratio
  if (unit_balance > 0) {
    verify_collateral_ratio(vault_ctx)
  }
}

/**
 * Verify each liquidated vault is eligible for liquidation.
 *
 * Step 2 of multi-vault liquidation verification:
 * - Each vault must be encumbered (has debt)
 * - Each vault must be underwater (liquid_price <= thold_price)
 *
 * @param liquid_profiles - Array of liquidated vault profiles
 * @throws Error if any vault is not eligible for liquidation
 */
export function verify_liquid_vaults_eligible (
  liquid_profiles : LiquidVaultProfile[]
) : void {
  for (const profile of liquid_profiles) {
    // Must be encumbered (has debt)
    Assert.ok(
      profile.unit_balance > 0,
      `liquidated vault has no debt: unit_balance=${profile.unit_balance}`
    )
    // Must be underwater
    Assert.exists(profile.thold_price, 'liquidated vault missing threshold price')
    Assert.exists(profile.liquid_price, 'liquidated vault missing liquidation price')
    Assert.ok(
      profile.liquid_price <= profile.thold_price,
      `vault not eligible for liquidation: price ${profile.liquid_price} > threshold ${profile.thold_price}`
    )
  }
}

/**
 * Verify each liquidated vault transition using core-ts 'liquidate' action.
 *
 * Step 3 of multi-vault liquidation verification:
 * - Builds the NEW state for each liquidated vault
 * - Calls core-ts verify_vault_request with 'liquidate' action type
 * - 'liquidate' action verifies: encumbered vault, underwater, root_txid unchanged
 *
 * @param vault_ctx - The vault request context for repo/trim
 * @throws Error if any liquidated vault transition is invalid
 */
export function verify_liquid_vault_transitions (
  vault_ctx : VaultRequestCtx<VaultBaseRequestConfig>
) : void {
  const { liquid_profiles, proto_profile, vault_action, vault_terms } = vault_ctx
  const vault_value_min = vault_terms.vault_value_min

  for (const prev_profile of liquid_profiles ?? []) {
    Assert.exists(prev_profile.vault_value, 'liquidated vault missing vault value')
    // Invariant: a vault profile's balance must equal its on-chain value
    // minus the protocol minimum (Codex F16). An untrusted
    // LiquidVaultProfile source can supply a correct vault_value for the
    // on-chain output but an inflated vault_balance for verification; the
    // new state derives from vault_balance, so check it before use.
    Assert.ok(
      prev_profile.vault_balance === prev_profile.vault_value - vault_value_min,
      `liquidated vault_balance invariant violated: ${prev_profile.vault_balance} !== ` +
      `${prev_profile.vault_value} - ${vault_value_min}`
    )
    // Build NEW state for this liquidated vault

    const new_vault_balance = get_new_liquidated_vault_balance(prev_profile, vault_action)
    const new_unit_balance  = get_new_liquidated_unit_balance(prev_profile, vault_action)

    // For liquidated vaults, use 'liquidate' action type which verifies:
    // - Previous vault was encumbered
    // - Vault was underwater (eligible for liquidation)
    // - Root txid unchanged
    const new_profile : VaultProfile = {
      ...prev_profile,
      vault_action   : 'liquidate',  // Use 'liquidate' action type (not 'repo'/'trim')
      vault_balance  : new_vault_balance,
      unit_balance   : new_unit_balance,
      vault_ratio    : null,
      vault_value    : new_vault_balance + vault_value_min,
      price_commits  : vault_action === 'trim' ? prev_profile.price_commits : [],
      price_stamp    : vault_action === 'trim' ? prev_profile.price_stamp : null,
      unit_price     : vault_action === 'trim' ? prev_profile.unit_price : null,
      thold_price    : vault_action === 'trim' ? prev_profile.thold_price : null
    }

    new_profile.vault_ratio = get_vault_profile_ratio(proto_profile, new_profile)

    // The spread of prev_profile (a LiquidVaultProfile) carries liquid_key
    // and liquid_price into new_profile, so the cast is safe at runtime;
    // verify_vault_liquidate enforces the breach chain on those fields.
    verify_vault_liquidate(proto_profile, new_profile as LiquidVaultProfile, prev_profile)
  }
}

/**
 * Verify liquidation amounts are internally consistent.
 *
 * Step 4 of multi-vault liquidation verification:
 * - reward_sats = claimed_sats - reserve_sats
 * - claimed_sats does not exceed vault_value
 * - For repo: claimed_unit equals unit_balance (full liquidation)
 * - For trim: claimed_unit does not exceed unit_balance (partial liquidation)
 *
 * @param vault_ctx - The vault request context for repo/trim
 * @throws Error if liquidation amounts are inconsistent
 */
export function verify_liquidation_amounts (
  vault_ctx : VaultRequestCtx<VaultBaseRequestConfig>
) : void {
  const { liquid_profiles, proto_profile, vault_action } = vault_ctx
  const reserve_tolerance_sats = 1

  for (const profile of liquid_profiles ?? []) {
    // Verify the quote values are internally consistent
    // reward_sats = claimed_sats - reserve_sats
    Assert.ok(
      profile.reward_sats === profile.claimed_sats - profile.reserve_sats,
      `liquidation reward mismatch: ${profile.reward_sats} !== ${profile.claimed_sats} - ${profile.reserve_sats}`
    )

    // Verify claimed_sats doesn't exceed vault_value
    Assert.exists(profile.vault_value, 'liquidated vault missing vault value')
    Assert.ok(
      profile.claimed_sats <= profile.vault_value,
      `claimed sats exceeds vault value: ${profile.claimed_sats} > ${profile.vault_value}`
    )

    // For repo (full liquidation), claimed_unit should equal unit_balance
    if (vault_action === 'repo') {
      Assert.ok(
        profile.claimed_unit === profile.unit_balance,
        `repo should claim all debt: ${profile.claimed_unit} !== ${profile.unit_balance}`
      )
    }

    // For trim (partial), claimed_unit should be less than or equal to unit_balance
    if (vault_action === 'trim') {
      Assert.ok(
        profile.claimed_unit <= profile.unit_balance,
        `trim cannot claim more than debt: ${profile.claimed_unit} > ${profile.unit_balance}`
      )
    }

    // Reserve should be paid from the over-collateralized premium, not principal debt.
    Assert.exists(profile.liquid_price, 'liquidated vault missing liquidation price for reserve validation')
    // Trust-boundary: adjust liquid_price into base-units-per-BTC.
    const adjusted_unit_price = get_adjusted_liquid_price(proto_profile, profile.liquid_price)
    const debt_value_sats     = convert_unit_to_sats(profile.claimed_unit, adjusted_unit_price)
    const premium_sats        = Math.max(profile.claimed_sats - debt_value_sats, 0)

    Assert.ok(
      profile.reserve_sats <= (premium_sats + reserve_tolerance_sats),
      `reserve exceeds premium: reserve=${profile.reserve_sats}, premium=${premium_sats}, claimed_sats=${profile.claimed_sats}, debt_sats=${debt_value_sats}, liquid_price=${profile.liquid_price}`
    )
  }
}

function get_new_liquidated_vault_balance (
  liquid_profile : LiquidVaultProfile,
  vault_action   : VaultAction
) : number {
  if (vault_action === 'repo') {
    return 0  // Repo: vault is fully cleared
  }
  const new_vault_balance = liquid_profile.vault_balance - liquid_profile.claimed_sats  // Trim: partial
  if (new_vault_balance < 0) {
    throw new Error(`new vault balance is negative: ${new_vault_balance} < 0`)
  }
  return new_vault_balance
}

function get_new_liquidated_unit_balance (
  liquid_profile : LiquidVaultProfile,
  vault_action   : VaultAction
) : number {
  if (vault_action === 'repo') {
    return 0  // Repo: vault is fully cleared
  }
  const new_unit_balance = liquid_profile.unit_balance - liquid_profile.claimed_unit  // Trim: partial
  if (new_unit_balance < 0) {
    throw new Error(`new unit balance is negative: ${new_unit_balance} < 0`)
  }
  return new_unit_balance
}
