/**
 * @fileoverview Calculates unit and vault balance changes for a vault action.
 */

import { get_vault_terms } from '@ducat-unit/core/lib'
import { VaultError }      from '@/lib/errors/index.js'

import type { VaultActionConfig } from '@/types/index.js'

/**
 * Calculate the unit and vault balances for a given vault action.
 *
 * @param vault_config  - The vault config.
 * @param txfee_balance - The txfee balance.
 * @returns The unit and vault balances.
 */
export function tabulate_vault_balance (
  vault_config  : VaultActionConfig,
  txfee_balance : number
) : number {
  // Unpack the vault config.
  const {
    deposit_amount  = 0,
    liquid_profiles = [],
    proto_profile,
    vault_action,
    vault_profile,
    withdraw_amount = 0
  } = vault_config

  // Define the reserve sats amount.
  const vault_terms = get_vault_terms(proto_profile.proto_terms)

  // Define the previous vault balance.
  const prev_sats_balance = vault_profile?.vault_balance ?? 0

  // Define the reward sats balances.
  const reserve_sats = liquid_profiles.reduce((acc, profile) => acc + profile.reserve_sats, 0)
  const reward_sats  = liquid_profiles.reduce((acc, profile) => acc + profile.reward_sats,  0)

  // Check if the reserve is payable.
  const payable_reserve = (reserve_sats >= vault_terms.reserve_sats_min)

  // Set the reward balance.
  const reward_balance  = (payable_reserve) ? reward_sats  : reward_sats + reserve_sats

  // Define the vault value.
  let vault_balance : number = 0

  // Switch on the vault action.
  switch (vault_action) {
    case 'open':
      vault_balance = deposit_amount - vault_terms.vault_value_min
      break
    case 'borrow':
      vault_balance = prev_sats_balance + deposit_amount
      break
    case 'repay':
      vault_balance = prev_sats_balance + deposit_amount
      break
    case 'deposit':
      vault_balance = prev_sats_balance + deposit_amount
      break
    case 'withdraw':
      vault_balance = prev_sats_balance - withdraw_amount
      break
    case 'close':
      // Close can spend both tracked collateral and the locked vault minimum.
      vault_balance = prev_sats_balance + vault_terms.vault_value_min
      break
    case 'repo':
    case 'trim':
      vault_balance = prev_sats_balance + reward_balance + deposit_amount
      break
    default:
      throw new VaultError(`invalid vault action: ${vault_action}`)
  }
  // Subtract the txfee balance from the vault balance.
  vault_balance = vault_balance - txfee_balance
  // Return the unit and vault balances.
  return vault_balance
}

/**
 * Calculate reserve payout balance from liquidation profiles.
 *
 * @param vault_config - Vault action config with liquidation profile data.
 * @returns Reserve sats that should be paid out for this action.
 */
export function tabulate_reserve_balance (
  vault_config : VaultActionConfig
) : number {
  // Unpack the vault config.
  const { liquid_profiles, proto_profile } = vault_config
  // Define the reserve sats amount.
  const vault_terms = get_vault_terms(proto_profile.proto_terms)
  // Define the reward sats balances.
  const reserve_sats = liquid_profiles?.reduce((acc, profile) => acc + profile.reserve_sats, 0) ?? 0
  // Check if the reserve is payable.
  const payable_reserve = (reserve_sats >= vault_terms.reserve_sats_min)
  // Set the reserve and reward balances.
  return (payable_reserve) ? reserve_sats : 0
}

/**
 * Calculate the unit balance for a given vault action.
 *
 * @param vault_config - The vault config.
 * @returns The unit balance.
 */
export function tabulate_unit_balance (
  vault_config : VaultActionConfig
) : number {
  // Unpack the vault config.
  const {
    borrow_amount   = 0,
    liquid_profiles = [],
    repay_amount    = 0,
    vault_action,
    vault_profile
  } = vault_config
  // Define the previous unit and vault balances.
  const prev_unit_balance = vault_profile?.unit_balance ?? 0
  // Define the claimed unit from liquidation.
  const claimed_unit = liquid_profiles.reduce((acc, profile) => acc + profile.claimed_unit, 0)
  // Define the unit balance.
  let unit_balance : number = 0
  // Switch on the vault action.
  switch (vault_action) {
    case 'open':
      unit_balance = borrow_amount
      break
    case 'borrow':
      unit_balance = prev_unit_balance + borrow_amount
      break
    case 'repay':
      unit_balance = prev_unit_balance - repay_amount
      break
    case 'deposit':
    case 'withdraw':
      unit_balance = prev_unit_balance
      break
    case 'close':
      unit_balance = 0
      break
    case 'repo':
    case 'trim':
      unit_balance = prev_unit_balance + claimed_unit
      break
    default:
      throw new VaultError(`invalid vault action: ${vault_action}`)
  }
  // Return the unit balance.
  return unit_balance
}
