/**
 * @fileoverview Vault price/collateral math helpers and the SDK's unit-conversion boundary.
 *
 * ## Unit convention
 *
 * All UNIT-denominated amounts in `client-sdk` source code are in
 * **smallest-divisible base units** of the relevant asset (per `asset_profile.div`).
 *
 * Oracle prices arrive in **display-units-per-BTC** (e.g., `base_price = 50_000`
 * for a $50k/BTC quote against a UNIT stablecoin). They are converted to
 * **base-units-per-BTC** by exactly one of the three helpers below:
 * `get_adjusted_quote_price`, `get_adjusted_commit_price`, `get_adjusted_liquid_price`.
 *
 * Once a price has crossed one of these boundary helpers, downstream math
 * (`calc_collateral_ratio`, `convert_unit_to_sats`, `get_max_sats_at_ratio`, etc.)
 * must NOT re-apply divisibility. The helpers are the trust boundary.
 *
 * Display formatting (UI labels, log messages with "$X.YY") belongs to
 * presentation-layer code only. No helper in `src/` returns display-unit values.
 */

import { Assert }                        from '@vbyte/util'
import { DEFAULT_POSTAGE, SATS_PER_BTC } from '@/const.js'
import { get_unit_asset_id }             from '@/lib/index.js'

import {
  calc_collateral_ratio,
  count_steps_scaled,
  floor_to_precision,
  get_adjusted_unit_price,
  get_asset_pool,
  get_asset_profile,
  get_bucket_rate,
  get_decimal_count,
  get_price_contract_commit_hash,
  get_threshold_price,
  get_vault_terms,
  select_base_price_quote,
  validate_price_quote
} from '@ducat-unit/core/lib'

import type {
  VaultActionBalance,
  VaultActionConfig
} from '@/types/index.js'

import type {
  PriceCommitData,
  PriceQuote,
  ProtoProfile
} from '@ducat-unit/core'

/**
 * Trust boundary: adjust an oracle `PriceQuote.base_price` into base-units-per-BTC.
 *
 * The returned value is suitable for direct use by `calc_collateral_ratio`,
 * `convert_unit_to_sats`, `get_max_sats_at_ratio`, and any downstream collateral
 * math. Callers must NOT re-apply divisibility to the result.
 *
 * @param proto_profile - The protocol profile (carries the UNIT asset's `div`).
 * @param price_quote   - A price quote with `base_price` in display-units-per-BTC.
 * @returns Adjusted unit price in base-units-per-BTC.
 */
export function get_adjusted_quote_price (
  proto_profile : ProtoProfile,
  price_quote   : PriceQuote
) : number {
  const vault_terms   = get_vault_terms(proto_profile.proto_terms)
  const asset_profile = get_asset_profile(proto_profile, vault_terms.unit_asset_id)
  return get_adjusted_unit_price(price_quote.base_price, asset_profile.div)
}

/**
 * Trust boundary: adjust a `PriceCommitData.base_price` into base-units-per-BTC.
 *
 * Same semantics as `get_adjusted_quote_price` but for `PriceCommitData` shapes
 * (used in vault profiles and witness commits).
 *
 * @param proto_profile - The protocol profile (carries the UNIT asset's `div`).
 * @param price_commit  - A price commit with `base_price` in display-units-per-BTC.
 * @returns Adjusted unit price in base-units-per-BTC.
 */
export function get_adjusted_commit_price (
  proto_profile : ProtoProfile,
  price_commit  : PriceCommitData
) : number {
  const vault_terms   = get_vault_terms(proto_profile.proto_terms)
  const asset_profile = get_asset_profile(proto_profile, vault_terms.unit_asset_id)
  return get_adjusted_unit_price(price_commit.base_price, asset_profile.div)
}

/**
 * Trust boundary: adjust a raw `liquid_price` value into base-units-per-BTC.
 *
 * Same semantics as the price-shape helpers but for the bare numeric `liquid_price`
 * field on `LiquidVaultProfile`. Use this anywhere a `liquid_price` flows into
 * `convert_unit_to_sats` or any other collateral-math primitive.
 *
 * @param proto_profile - The protocol profile (carries the UNIT asset's `div`).
 * @param liquid_price  - A liquidation price in display-units-per-BTC.
 * @returns Adjusted liquid price in base-units-per-BTC.
 */
export function get_adjusted_liquid_price (
  proto_profile : ProtoProfile,
  liquid_price  : number
) : number {
  const vault_terms   = get_vault_terms(proto_profile.proto_terms)
  const asset_profile = get_asset_profile(proto_profile, vault_terms.unit_asset_id)
  return get_adjusted_unit_price(liquid_price, asset_profile.div)
}

/**
 * Determines the price bucket rate for a contract based on its collateralization level.
 *
 * Price buckets are discrete rate intervals used to group contracts by their
 * collateralization ratios. This function calculates which bucket a contract
 * falls into based on its asset value and debt balance.
 *
 * Collateral ratios outside the quote's published `[rate_min, rate_max]` range are
 * clamped into it rather than rejected: an over-collateralized vault snaps to the
 * highest (safest, lowest-threshold) bucket, and an under-collateralized or
 * zero-debt vault snaps to the lowest (most-aggressive) bucket. This guarantees the
 * selected bucket corresponds to a contract the oracle actually published.
 *
 * @param price_quote      - The price quote defining the rate range and step size.
 * @param collateral_ratio - The collateralization ratio of the contract.
 * @returns The bucket rate, floored to the step size precision.
 */
export function get_price_bucket_rate (
  price_quote      : PriceQuote,
  collateral_ratio : number
) : number {
  // Validate the price quote.
  validate_price_quote(price_quote)
  // Unpack the price quote.
  const { rate_min, rate_max, step_size } = price_quote
  // Get the decimal precision of the step size.
  const decimal_count = get_decimal_count(step_size)
  // Calculate the contract collateral rate (floored to step precision).
  const contract_rate = floor_to_precision(collateral_ratio, decimal_count)
  // Clamp into the oracle's published [rate_min, rate_max] range so out-of-range
  // ratios (over-collateralized, under-collateralized, or zero-debt) still select a
  // published bucket instead of throwing.
  const clamped_rate = Math.min(Math.max(contract_rate, rate_min), rate_max)
  // Calculate the number of steps using integer-scaled arithmetic to
  // avoid IEEE 754 drift (e.g. (1.99 - 1.6) / 0.01 = 38.999… not 39).
  const step_count  = count_steps_scaled(clamped_rate, rate_min, step_size)
  // Reconstruct the bucket rate via the shared helper, which mirrors the oracle's
  // enumeration exactly. NOT `step_count * step_size + rate_min` — that reintroduces
  // IEEE 754 drift (e.g. 359 * 0.01 + 1.35 = 4.9399999999999995, which would floor
  // down to 4.93) and cause a commit-hash mismatch against the oracle's 4.94 contract.
  return get_bucket_rate(rate_min, step_size, step_count)
}

/**
 * Report whether `collateral_ratio` falls outside the quote's published
 * `[rate_min, rate_max]` range and would therefore be clamped by
 * `get_price_bucket_rate`.
 *
 * The clamp is correct by design (an out-of-range ratio still selects a
 * published bucket), but it is silent. A caller that wants to surface a
 * wildly mis-collateralized vault can check this predicate and log/flag at its
 * own observability layer before (or instead of) selecting a bucket — these
 * math helpers stay pure and take no logging context.
 *
 * @param price_quote      - The price quote defining the rate range and step size.
 * @param collateral_ratio - The collateralization ratio to test.
 * @returns `true` if the ratio is outside the published range (would be clamped).
 */
export function is_ratio_clamped (
  price_quote      : PriceQuote,
  collateral_ratio : number
) : boolean {
  // Validate the price quote.
  validate_price_quote(price_quote)
  // Unpack the rate range and step size.
  const { rate_min, rate_max, step_size } = price_quote
  // Floor the ratio to step precision, mirroring get_price_bucket_rate.
  const contract_rate = floor_to_precision(collateral_ratio, get_decimal_count(step_size))
  // Clamped iff the floored rate sits outside the published range.
  return contract_rate < rate_min || contract_rate > rate_max
}

/**
 * Compute the per-quote price-commit hashes for a vault action.
 *
 * Internally crosses the price-adjustment trust boundary via
 * `get_adjusted_quote_price` and then passes the resulting base-units-per-BTC
 * value into `calc_collateral_ratio`. Inputs `action_quote.vault_balance` (sats)
 * and `action_quote.unit_balance` (base units) follow the SDK convention.
 *
 * @param proto_profile - Protocol profile (carries UNIT asset divisibility).
 * @param action_quote  - Projected vault/unit balances after the action.
 * @param price_quotes  - Available price quotes for bucket placement.
 * @returns Price contract commit hashes, one per input quote.
 */
export function get_price_commit_hashes (
  proto_profile : ProtoProfile,
  action_quote  : VaultActionBalance,
  price_quotes  : PriceQuote[]
) : string[] {
  // Unpack the action quote.
  const { vault_balance, unit_balance } = action_quote
  // Select the base price quote.
  const base_quote = select_base_price_quote(price_quotes)
  // Assert that a base price quote was found.
  Assert.exists(base_quote, 'no price quote found')
  // Get the adjusted unit price.
  const unit_price = get_adjusted_quote_price(proto_profile, base_quote)
  // Calculate the collateral ratio.
  const collateral_ratio = calc_collateral_ratio(vault_balance, unit_balance, unit_price)
  // Initialize the price contract parameters array.
  const hashes : string[] = []
  // For each price quote,
  for (const price_quote of price_quotes) {
    // Calculate the bucket rate.
    const bucket_rate = get_price_bucket_rate(price_quote, collateral_ratio)
    // Calculate the threshold price.
    const thold_price = get_threshold_price(price_quote, bucket_rate)
    // Get the price commit hash.
    const commit_hash = get_price_contract_commit_hash(price_quote, thold_price)
    // Add the price commit hash to the array.
    hashes.push(commit_hash)
  }
  // Return the price commit hashes array.
  return hashes
}

/**
 * Get the number of vault guardians.
 *
 * @param action_config - The action config.
 * @returns The number of vault guardians.
 */
export function get_vault_guardian_count (
  action_config : VaultActionConfig
): number {
  // Unpack the action config.
  const { guard_members, vault_profile } = action_config
  // If the vault guards are provided, return the length.
  if (guard_members) return guard_members.length
  // If the vault profile is provided, return the length.
  if (vault_profile) return vault_profile.guard_members.length
  // Otherwise, throw an error.
  throw new Error('guard membership missing from action config')
}

/** Count price oracles participating in the current action configuration. */
export function get_price_oracle_count (
  action_config : VaultActionConfig
): number {
  // Unpack the action config.
  const { price_quotes, vault_profile } = action_config
  // Prefer oracle count from the existing vault script tree when available.
  // Price commits may still be present on cleared profiles during transitional
  // states, and fee sizing should follow the committed script set.
  if (vault_profile) {
    const profile_oracle_count = vault_profile.price_commits?.length ?? 0
    if (profile_oracle_count > 0) return profile_oracle_count
  }
  // Otherwise fall back to caller-provided quote set (open or re-encumber paths).
  if (price_quotes) return price_quotes.length
  // Otherwise, return 0.
  return 0
}

/**
 * Checks if a repay action will produce asset change (excess UNIT).
 *
 * @param action_config - The action config.
 * @returns True if asset inputs contain more UNIT than the repay amount.
 */
export function has_asset_change (
  action_config : VaultActionConfig
): boolean {
  // Unpack the action config.
  const { repay_amount, asset_inputs, proto_profile } = action_config
  // If the repay amount or asset inputs are not provided, return false.
  if (!repay_amount || !asset_inputs) return false
  // Get the unit asset ID.
  const unit_asset_id = get_unit_asset_id(proto_profile)
  // Get the asset input size.
  const asset_pool    = get_asset_pool(unit_asset_id, asset_inputs)
  // Get the has asset change.
  return (asset_pool.pool_active > repay_amount)
}

/**
 * Determines the postage amount needed for a vault action.
 * Postage is the satoshi value assigned to UNIT-bearing outputs.
 *
 * @param vault_config - Configuration containing action type and optional postage
 * @returns Postage amount in satoshis (default 1000 sats)
 */
export function get_vault_action_postage (
  action_config : VaultActionConfig
) : number {
  // Unpack the vault config.
  const { unit_postage = DEFAULT_POSTAGE, vault_action } = action_config
  // Switch on the vault action.
  switch (vault_action) {
    case 'open':
      // Return the unit postage.
      return unit_postage
    case 'borrow':
      // Return the unit postage.
      return unit_postage
    case 'repay':
      // If there is asset change, return the unit postage.
      return has_asset_change(action_config) ? unit_postage : 0
    // The remaining actions produce no UNIT-bearing change output, so zero
    // postage is correct and safe for each. They are enumerated explicitly
    // (rather than handled by a fail-open default) so that any new or unknown
    // vault action fails closed in the default branch below.
    case 'close':
    case 'deposit':
    case 'withdraw':
    case 'repo':
    case 'trim':
    case 'liquidate':
      return 0
    default:
      // Fail closed: an unrecognized vault action must not silently produce a
      // (potentially unsafe) zero-postage output.
      throw new Error(`get_vault_action_postage: unhandled vault action: ${vault_action}`)
  }
}

/**
 * Calculate maximum satoshis allowed at a target collateral ratio.
 *
 * Formula: max_sats = (ratio * unit_balance * SATS_PER_BTC) / unit_price
 *
 * @param target_ratio - The target collateral ratio (e.g., 5.0 for 500%)
 * @param unit_balance - The vault's UNIT balance (debt)
 * @param unit_price   - The adjusted unit price (from get_base_unit_price)
 * @returns Maximum satoshis allowed at the target ratio
 */
export function get_max_sats_at_ratio (
  target_ratio : number,
  unit_balance : number,
  unit_price   : number
) : number {
  // If unit_balance is zero, there's no debt constraint.
  if (unit_balance === 0) return Number.MAX_SAFE_INTEGER
  // Calculate max sats using the collateral ratio formula inverted.
  const max_sats = (target_ratio * unit_balance * Number(SATS_PER_BTC)) / unit_price
  // Return floored value to be conservative.
  return Math.floor(max_sats)
}

/**
 * Calculate excess collateral when vault ratio would exceed rate_max.
 *
 * This function is used during repay operations to determine how much
 * collateral needs to be automatically withdrawn to keep the vault
 * within the maximum collateral ratio (rate_max).
 *
 * @param vault_balance - The vault's collateral balance in satoshis
 * @param unit_balance  - The vault's UNIT balance (debt) after repayment
 * @param price_quotes  - Array of price quotes for price validation
 * @param proto_profile - The protocol profile for accessing vault terms
 * @returns Excess satoshis to withdraw, or 0 if no overflow
 */
export function get_collateral_overflow (
  vault_balance : number,
  unit_balance  : number,
  price_quotes  : PriceQuote[],
  proto_profile : ProtoProfile
) : number {
  // If unit_balance is zero, no ratio constraint applies (vault is cleared).
  if (unit_balance === 0) return 0
  // If no price quotes, cannot calculate overflow.
  if (price_quotes.length === 0) return 0
  // Select the base price quote.
  const base_quote = select_base_price_quote(price_quotes)
  // If no base quote, cannot calculate overflow.
  if (!base_quote) return 0
  // Get the adjusted unit price.
  const unit_price = get_adjusted_quote_price(proto_profile, base_quote)
  // Calculate max sats at rate_max.
  const max_sats = get_max_sats_at_ratio(base_quote.rate_max, unit_balance, unit_price)
  // Calculate overflow (excess collateral).
  const overflow = vault_balance - max_sats
  // Return overflow if positive, otherwise 0.
  return Math.max(overflow, 0)
}
