/**
 * @fileoverview ProtoWallet - Reference wallet implementation for DUCAT vaults.
 *
 * The ProtoWallet provides a complete wallet interface for interacting with
 * the DUCAT protocol. It handles:
 *
 * - **Account Management**: Tracks funds, assets, and vault addresses
 * - **PSBT Signing**: Signs vault transactions (single and batch)
 * - **UTXO Fetching**: Retrieves spendable UTXOs for transaction building
 *
 * ## Connector Pattern
 *
 * The wallet uses a connector pattern to abstract signing and fetching operations.
 * This allows different implementations (hardware wallets, hot wallets, etc.) to
 * provide their own signing logic while using the same wallet interface.
 *
 * ## Usage
 *
 * ```typescript
 * import { ProtoWallet } from '@ducat-unit/client-sdk/wallet'
 *
 * const wallet = new ProtoWallet(accounts, connector, {
 *   chain_network: 'mainnet',
 *   txfee_rate: 5,
 * })
 *
 * // Sign a PSBT
 * const signed = await wallet.sign.psbt(unsigned_psbt)
 *
 * // Fetch UTXOs
 * const utxos = await wallet.fetch.funds()
 * ```
 *
 * @module wallet/class/wallet
 */

import { get_wallet_accounts }   from '../lib/account.js'
import { get_psbt_manifest_api } from '../lib/manifest.js'
import { get_observe_context }   from '@/lib/observe/index.js'

import {
  fetch_assets_api,
  fetch_funds_api,
  fetch_vaults_api,
} from '../lib/fetch.js'

import {
  sign_psbt_api,
  sign_batch_api
} from '../lib/sign.js'

import type {
  ProtoWalletAccountAPI,
  ProtoWalletAccountData,
  ProtoWalletConfig,
  ProtoWalletConnectAPI,
  ProtoWalletOptions,
} from '../types/index.js'
import type { ObserveContext } from '@/lib/observe/index.js'

const DEFAULT_CONFIG : ProtoWalletConfig = {
  asset_postage : 1_000,
  chain_network : 'regtest',
  txfee_rate    : 1,
  txfee_reserve : 1_000,
}

export class ProtoWallet {

  private readonly _acct : ProtoWalletAccountData
  private readonly _conf : ProtoWalletConfig
  private readonly _conn : ProtoWalletConnectAPI
  private readonly _observe : ObserveContext

  constructor (
    accounts  : ProtoWalletAccountAPI,
    connector : ProtoWalletConnectAPI,
    options   : ProtoWalletOptions
  ) {
    const config = get_config(options)
    this._acct   = get_wallet_accounts(accounts, config.chain_network)
    this._conf   = config
    this._conn   = connector
    this._observe = get_observe_context(options.observability, {
      module  : 'wallet',
      network : config.chain_network
    })
  }

  get account () : ProtoWalletAccountData {
    return this._acct
  }

  get config () {
    return this._conf
  }

  get connector () {
    return this._conn
  }

  get observe () {
    return this._observe
  }

  get fetch () {
    return {
      assets   : fetch_assets_api(this),
      funds    : fetch_funds_api(this),
      manifest : get_psbt_manifest_api(this),
      vaults   : fetch_vaults_api(this)
    }
  }

  get sign () {
    return {
      batch : sign_batch_api(this),
      coins : this.connector.sign.coins(this),
      psbt  : sign_psbt_api(this)
    }
  }
}

function get_config (options : ProtoWalletOptions) : ProtoWalletConfig {
  const {
    asset_postage,
    chain_network,
    txfee_rate,
    txfee_reserve
  } = options

  return {
    ...DEFAULT_CONFIG,
    ...(asset_postage !== undefined ? { asset_postage } : {}),
    ...(chain_network !== undefined ? { chain_network } : {}),
    ...(txfee_rate    !== undefined ? { txfee_rate }    : {}),
    ...(txfee_reserve !== undefined ? { txfee_reserve } : {})
  }
}
